// ─────────────────────────────────────────────────────────────────────
//  Fog-line setback model
//
//  Spawn code asks "how far past the white shoulder stripe should this
//  building's NEAR edge sit?", measured in player-car widths.  The
//  building's CENTER offset (what the renderer + collision actually
//  consume) is then `fogLineOffset + side * (carWidthsPastFog *
//  CAR_WIDTH_NORM + buildingHalfWidthNorm)`.
//
//  Why:
//    The previous model used a fixed center offset (`2.05`) regardless
//    of how wide the building was — a 1-unit-wide cottage and an
//    8-unit-wide skyline cluster both spawned with their CENTER at the
//    same place, which put the cottage's near edge a car-width past
//    the fog line but the skyline cluster's near edge halfway across
//    the road.  This helper inverts that: callers pick the visible
//    GAP between road shoulder and building face, and the math here
//    figures out the center offset by adding back the building's own
//    half-width.
//
//  Math (per call):
//    targetW_screen = proj.sw * mult       // mult = profile's heightMult * aspect,
//                                          //        or profile's widthMult,
//                                          //        or default sizeMult (2.6).
//    halfW_norm     = (targetW_screen / 2) / proj.roadHalfW
//                   = (mult / 2) * (proj.sw / proj.roadHalfW)
//                   = (mult / 2) * (825 / 3600)               // SW_TO_ROADHALF
//                   = (mult / 2) * 0.22917
//    offset         = sign * (FOG_LINE_OFFSET
//                            + carWidthsPastFog * CAR_WIDTH_NORM
//                            + halfW_norm)
//
//  The mult lookup matches SCENERY_IMAGE_PROFILES in GameScene.js for
//  every keyed photo asset we spawn through here; unknown textures fall
//  back to the procedural defaults (sizeMult 2.6 = wide house/tower
//  silhouette).
// ─────────────────────────────────────────────────────────────────────
const FOG_LINE_OFFSET   = 1.0;          // white shoulder stripe in lane units
const SW_TO_ROADHALF    = 825 / 3600;   // proj.sw / proj.roadHalfW (constant)
const CAR_WIDTH_NORM    = SW_TO_ROADHALF; // ~0.229 — a player car's width in normalized lane units

// Mirror the subset of SCENERY_IMAGE_PROFILES (GameScene.js) we need
// for spawn-time half-width math.  Each entry yields an effective
// width-multiplier-on-proj.sw: either widthMult directly, or
// heightMult * (textureAspectGuess). For residential frontage, use
// source-PNG aspect ratios so the fixed spawn position matches runtime
// uncapped image sizing exactly.
// Keys not listed fall back to FOG_DEFAULT_MULT below.
const FOG_PROFILE_MULTS = {
  // West Seattle homes — actual source ratios, matching runtime sizing.
  west_seattle_1: 6.0 * (1536 / 1024),
  west_seattle_2: 6.0 * (1448 / 1086),
  west_seattle_3: 6.0 * (1459 / 1078),
  west_seattle_4: 6.0 * (1415 / 1112),
  west_seattle_5: 6.0 * (1536 / 1024),
  west_seattle_6: 6.0 * (1536 / 1024),
  // Bellevue skyline — wider cluster art (aspect ~1.6-2.4).
  codex_bellevue_skyline:             6.0 * 2.40,
  codex_bellevue_wavy_residential:    6.0 * 0.95,
  codex_bellevue_city_center_dark:    6.0 * 1.00,
  codex_bellevue_braced_glass_tower:  6.0 * 0.90,
  codex_bellevue_residential_cluster: 6.0 * 2.20,
  codex_pse_bellevue_office_left:         6.0 * 1.30,
  codex_pse_bellevue_office_right:        6.0 * 1.30,
  codex_pse_bellevue_second_office_left:  6.0 * 1.40,
  codex_pse_bellevue_second_office_right: 6.0 * 1.40,
  codex_bellevue_twin_residential_left:   6.0 * 1.50,
  // Downtown Seattle skyline — tall + relatively narrow.
  codex_seattle_skyline:              3.90 * 2.40,
  codex_seattle_office_cluster:       3.80 * 2.40,
  codex_seattle_tower_pair:           4.60 * 0.80,
  codex_seattle_columbia_center:      5.90 * 0.55,
  codex_seattle_rainier_square:       5.45 * 0.85,
  codex_seattle_two_union_square:     5.35 * 0.85,
  codex_seattle_1201_third:           5.15 * 0.80,
  codex_seattle_municipal_tower:      5.05 * 0.95,
  codex_seattle_f5_tower:             5.25 * 0.70,
  codex_seattle_safeco_plaza:         4.70 * 0.95,
  codex_seattle_city_centre:          4.55 * 0.95,
  codex_seattle_russell_investments:  4.55 * 1.10,
  // Issaquah frontage — actual source ratios, matching runtime sizing.
  codex_issaquah_front_supply:        4.80 * (1533 / 926),
  codex_issaquah_highlands:           4.80 * (1514 / 894),
  codex_issaquah_cottage:             4.40 * (1524 / 928),
};
// Default for unknown textures + procedural houses/towers (sp.type
// 'house' or 'building' with no profile lookup).  Matches sizeMult
// default 2.6 in GameScene._renderSceneSprites.
const FOG_DEFAULT_MULT = 2.6;

/**
 * Return the absolute lateral offset (signed, normalized lane units)
 * that places a building's NEAR edge `carWidthsPastFog` car-widths
 * outboard of the fog line on the chosen side.
 *
 *   texKey               — texture key (used to estimate building width).
 *   side                 — +1 (right of road) or -1 (left of road).
 *   carWidthsPastFog     — gap between fog line and building's near edge,
 *                          in player-car widths.  0 = touching the white
 *                          stripe.  Negative values are clamped to 0.
 *   widthMultOverride    — optional explicit effective widthMult (used
 *                          when caller knows the asset's per-segment
 *                          override better than the FOG_PROFILE_MULTS
 *                          table — e.g. heightBoost cases).
 *
 *  Why: lets spawn sites express placement in human terms ("one car
 *  width past the shoulder") without needing to back-solve for the
 *  building's center.  See block comment above.
 */
function fogLineOffset(texKey, side, carWidthsPastFog, widthMultOverride) {
  const sign = side >= 0 ? 1 : -1;
  const gap  = Math.max(0, carWidthsPastFog) * CAR_WIDTH_NORM;
  const mult = widthMultOverride
            ?? FOG_PROFILE_MULTS[texKey]
            ?? FOG_DEFAULT_MULT;
  const halfW = (mult * 0.5) * SW_TO_ROADHALF;
  return sign * (FOG_LINE_OFFSET + gap + halfW);
}

function getTraitsAt(t) {
  for (const r of REGION_ORDER) {
    if (t >= r.start && t < r.end) return REGION_TRAITS[r.key];
  }
  // Fallback to last region (covers t === 1.0 edge case + any out-of-range t).
  const last = REGION_ORDER[REGION_ORDER.length - 1];
  return REGION_TRAITS[last.key];
}

function smooth(arr, strength = 0.15) {
  const result = [...arr];
  for (let i = 1; i < arr.length; i++) {
    result[i] = result[i - 1] * (1 - strength) + arr[i] * strength;
  }
  return result;
}

// Centered box-blur — symmetric, no forward bias.  Apply multiple passes
// for a Gaussian-like response (3 passes ≈ Gaussian).  Used on hills[]
// so the elevation profile is smoother than what smoothstep keyframes
// give us by themselves (smoothstep has slope=0 at every keyframe, which
// stacks micro-humps when keyframes are tightly spaced).
function boxBlurCentered(arr, halfWidth, passes = 1) {
  let src = arr;
  for (let p = 0; p < passes; p++) {
    const n = src.length;
    const dst = new Array(n);
    let sum = 0;
    let count = 0;
    // Prime the window over [0, halfWidth]
    for (let j = 0; j <= Math.min(halfWidth, n - 1); j++) {
      sum += src[j];
      count++;
    }
    for (let i = 0; i < n; i++) {
      dst[i] = sum / count;
      const addIdx = i + halfWidth + 1;
      const dropIdx = i - halfWidth;
      if (addIdx < n) { sum += src[addIdx]; count++; }
      if (dropIdx >= 0) { sum -= src[dropIdx]; count--; }
    }
    src = dst;
  }
  return src;
}

// Interpolate a sampled array at progress t (0–1)
function sampleArr(arr, t) {
  const idx = t * (arr.length - 1);
  const lo  = Math.floor(idx);
  const hi  = Math.min(lo + 1, arr.length - 1);
  return arr[lo] + (arr[hi] - arr[lo]) * (idx - lo);
}

// Helper used by the tunnel-tagging block down below.  Inline rather than
// reaching for the SEGS_PER_MILE that's only defined later in the random-
// roadside-cop pass.
const SEGS_PER_MILE_FOR_TUNNEL = (count) => count / TOTAL_ROUTE_MILES;

export function buildRoute(count = ROUTE_SEGS) {
  const rng      = new SeededRNG(1337);
  const segments = [];

  // ── Curves ───────────────────────────────────────────────────────────
  const rawCurves = new Array(count).fill(0).map((_, i) => {
    const t      = i / count;
    const traits = getTraitsAt(t);
    if (HAS_REAL_CURVES) {
      // Real road curvature from hand-keyframed I-90 data, lightly blended
      // with per-region noise so the road still feels organic.
      const real  = clamp(sampleArr(geoData.curves, t), -0.022, 0.022);
      const noise = rng.range(-traits.curveMax * 0.25, traits.curveMax * 0.25);
      return real + noise;
    }
    const noise = rng.range(-traits.curveMax, traits.curveMax);
    const wave  = Math.sin(i * 0.003) * traits.curveMax * 0.7;
    return noise * 0.4 + wave * 0.6;
  });
  // ── Bridge & tunnel ranges ───────────────────────────────────────
  // Edge mile-markers (start..end) for every drivable bridge + tunnel
  // on the eastside.  Used below to (a) tag segments as bridge/tunnel
  // and (b) zero-out curvature so the road is dead-straight across
  // any bridge — no Washington bridge has a turn on it.
  const WEST_SEATTLE_BRIDGE_RANGE = [1.0, 1.7];   // high concrete over Duwamish (shifted: mile 0-1 is pre-bridge water-left approach)
  // The high West Seattle bridge crosses port land with two visible
  // Duwamish/slip channels under it. Keep crane yards on the dry spans.
  const WEST_SEATTLE_WATER_CHANNEL_RANGES = [
    [1.17, 1.25],
    [1.44, 1.52],
  ];
  const MT_BAKER_TUNNEL_RANGE     = [4.9, 5.6];   // west portal → east portal
  const MURROW_BRIDGE_RANGE       = [5.7, 7.2];   // Lacey V. Murrow floating bridge
  const MERCER_LID_TUNNEL_RANGE   = [7.4, 7.9];   // covered lid across Mercer Island
  const EAST_CHANNEL_BRIDGE_RANGE = [9.8, 10.2];  // Mercer → Bellevue
  const BRIDGE_RANGES = [WEST_SEATTLE_BRIDGE_RANGE, MURROW_BRIDGE_RANGE, EAST_CHANNEL_BRIDGE_RANGE];
  // Flatten the procedural curve noise across every bridge segment —
  // bridges on this route are straight in real life and the player
  // wreck-clamps badly if a curve drags them into the rail.
  for (const [m0, m1] of BRIDGE_RANGES) {
    const i0 = Math.floor((m0 / TOTAL_ROUTE_MILES) * count);
    const i1 = Math.floor((m1 / TOTAL_ROUTE_MILES) * count);
    for (let i = i0; i < i1; i++) rawCurves[i] = 0;
  }
  // Mt Baker Tunnel — real-world dead-straight (single bore aligned
  // east/west under the freeway lid).  Zero any noise across the
  // tunnel range so the procedural / GPS curve data can't push the
  // player into the concrete.
  {
    const [m0, m1] = MT_BAKER_TUNNEL_RANGE;
    const i0 = Math.floor((m0 / TOTAL_ROUTE_MILES) * count);
    const i1 = Math.floor((m1 / TOTAL_ROUTE_MILES) * count);
    for (let i = i0; i < i1; i++) rawCurves[i] = 0;
  }
  // Mercer Island Lid Tunnel — real-world I-90 bends RIGHT through
  // the lid as the freeway rounds the island ridge.  Add a half-sine
  // right-curve impulse so the in-game tunnel matches the actual
  // geometry instead of running straight through the rock.
  {
    const [m0, m1] = MERCER_LID_TUNNEL_RANGE;
    const i0 = Math.floor((m0 / TOTAL_ROUTE_MILES) * count);
    const i1 = Math.floor((m1 / TOTAL_ROUTE_MILES) * count);
    const peak = +0.012;                          // gentle right bend
    for (let i = i0; i < i1; i++) {
      const tt = (i - i0) / Math.max(1, i1 - i0);
      rawCurves[i] = peak * Math.sin(tt * Math.PI);
    }
  }
  const curves = smooth(rawCurves, 0.04);

  // ── Hills ────────────────────────────────────────────────────────────
  // Real-world I-90 / WA-26 / US-195 elevation profile from authoritative
  // sources (USGS, WSDOT, Wikipedia per-town elevations).  39 keyframes
  // capture every major topographic landmark on the 293-mi drive: the
  // hilltop start in West Seattle, the Duwamish descent to sea level,
  // the floating-bridge water crossing, the Mt. Baker tunnel, the climb
  // up the Cascades to Snoqualmie Pass (3022 ft), the Yakima River
  // canyon dip, Indian John Hill, Elk Heights, the dramatic
  // Ryegrass-Summit→Vantage drop into the Columbia gorge (~1965 ft over
  // 10 mi), the scabland coulees, and the rolling Palouse climb to
  // Pullman.  t = mile / 293.
  const I90_ELEV_FT = [
    [0.0000,   350],   //   0 mi:  West Seattle (Alaska Junction hilltop)
    [0.0020,   290],   //   0.6 mi: West Seattle Bridge west approach (deck climbing)
    [0.0033,   200],   //   1.0 mi: West Seattle Bridge midspan (high above Duwamish)
    [0.0044,    80],   //   1.3 mi: Off the bridge, descending into SoDo
    [0.0137,    20],   //   4.0 mi: SoDo (sea level)
    [0.0167,    55],   //   4.9 mi: Mt. Baker Tunnel west portal
    [0.0191,    55],   //   5.6 mi: Mt. Baker Tunnel east portal
    [0.0195,    30],   //   5.7 mi: Ramp down to the Lacey V. Murrow approach
    [0.0218,    18],   //   6.4 mi: Murrow Floating Bridge midspan (lake level)
    [0.0246,    25],   //   7.2 mi: Murrow east end / Mercer Island west shore
    [0.0252,    70],   //   7.4 mi: Mercer Island Lid Tunnel west portal (ridge top)
    [0.0270,    70],   //   7.9 mi: Mercer Island Lid Tunnel east portal
    [0.0290,    40],   //   8.5 mi: Gentle descent toward East Channel
    [0.0335,    25],   //   9.8 mi: East Channel Bridge approach (lake level)
    [0.0348,    30],   //  10.2 mi: East Channel Bridge end — Bellevue shore
    [0.0410,    92],   //  12 mi:  Bellevue (I-405 jct, climbing up)
    [0.0512,   200],   //  15 mi:  Eastgate climb
    [0.0580,   108],   //  17 mi:  Issaquah (valley floor)
    [0.0751,   450],   //  22 mi:  Preston / Tiger Mountain shoulder
    [0.0956,   420],   //  28 mi:  Snoqualmie / Fall City exit
    [0.1092,   525],   //  32 mi:  North Bend
    [0.1297,   900],   //  38 mi:  South Fork Snoqualmie (climb begins)
    [0.1536,  2000],   //  45 mi:  Denny Creek / Asahel Curtis
    [0.1706,  2600],   //  50 mi:  Hyak / Keechelus Lake west shore
    [0.1775,  3022],   //  52 mi:  SNOQUALMIE PASS SUMMIT
    [0.1877,  2650],   //  55 mi:  Hyak east / Keechelus Dam
    [0.2116,  2180],   //  62 mi:  Easton
    [0.2389,  2050],   //  70 mi:  Cabin Creek
    [0.2662,  1906],   //  78 mi:  Cle Elum
    [0.2901,  1950],   //  85 mi:  Thorp
    [0.3038,  2141],   //  89 mi:  Indian John Hill summit (rest area)
    [0.3413,  1600],   // 100 mi:  Yakima River canyon descent
    [0.3584,  1535],   // 105 mi:  Ellensburg (I-82 jct)
    [0.3925,  2359],   // 115 mi:  Elk Heights
    [0.4164,  2535],   // 122 mi:  Ryegrass Summit (highest east of pass)
    [0.4505,   570],   // 132 mi:  VANTAGE BRIDGE / Columbia River (lowest east)
    [0.4573,   900],   // 134 mi:  Climb out of river canyon (WA-26 begins)
    [0.4778,  1000],   // 140 mi:  Sand Hollow / Royal Slope
    [0.5119,  1027],   // 150 mi:  Royal City
    [0.5631,  1050],   // 165 mi:  Frenchman Hills crossing
    [0.6143,  1060],   // 180 mi:  Othello
    [0.6826,  1250],   // 200 mi:  Hatton Coulee plateau
    [0.7679,  1027],   // 225 mi:  Washtucna (in coulee floor)
    [0.8191,  1400],   // 240 mi:  Climb out of Washtucna Coulee
    [0.8532,  1475],   // 250 mi:  La Crosse
    [0.9044,  1800],   // 265 mi:  Dusty / Palouse rolling hills
    [0.9454,  1965],   // 277 mi:  Colfax (US-195 jct)
    [0.9727,  2400],   // 285 mi:  Climb up Palouse ridge
    [1.0000,  2352],   // 293 mi:  PULLMAN (WSU)
  ];
  // Catmull-Rom interpolation between keyframes — gives a globally
  // C1-continuous elevation curve (the slope at each keyframe matches
  // the chord between its neighbors instead of being forced to zero).
  // Smoothstep gave slope=0 at every keyframe, which stacked a tiny
  // "wave" into each span and made the road feel bumpy when keyframes
  // were closely spaced (Mercer Island, North Bend descent, the tunnels).
  const elevAt = (t) => {
    const kf = I90_ELEV_FT;
    const n  = kf.length;
    if (t <= kf[0][0])     return kf[0][1];
    if (t >= kf[n - 1][0]) return kf[n - 1][1];
    let i = 0;
    for (; i < n - 1; i++) if (t <= kf[i + 1][0]) break;
    const p0 = kf[Math.max(0, i - 1)][1];
    const p1 = kf[i][1];
    const p2 = kf[i + 1][1];
    const p3 = kf[Math.min(n - 1, i + 2)][1];
    const span = kf[i + 1][0] - kf[i][0];
    const u    = span > 0 ? (t - kf[i][0]) / span : 0;
    const u2   = u * u;
    const u3   = u2 * u;
    // Catmull-Rom matrix, tension = 0.5.
    return 0.5 * (
      (2 * p1) +
      (-p0 + p2) * u +
      (2 * p0 - 5 * p1 + 4 * p2 - p3) * u2 +
      (-p0 + 3 * p1 - 3 * p2 + p3) * u3
    );
  };

  // World elevation is absolute, not an accumulated random walk. Keep the
  // pavement profile clean and macro-scale: the real-route keyframes create
  // the climbs and descents, while the road surface itself stays smooth.
  // ELEV_SCALE doubled (340 → 680) per user request to make hills look
  // about 2× as steep visually.  Important: realGradePct (line below)
  // divides dY by ELEV_SCALE, so the scale CANCELS OUT of the physics
  // grade — gradePct stays unchanged, meaning the camera pitch boost,
  // grade-based speed multiplier, and grade-sign placement all see
  // exactly the same real-world percentages as before.  Only seg.y
  // (the road's vertical world coordinate) doubles, which is what
  // drives the visual climbs/descents.
  const ELEV_SCALE = 680;
  const baseElevFt = elevAt(0);
  const rawHills = new Array(count).fill(0).map((_, i) => {
    const t = i / count;
    if (HAS_REAL_HILLS) {
      return sampleArr(geoData.hills, t) * ELEV_SCALE;
    }
    return (elevAt(t) - baseElevFt) * ELEV_SCALE;
  });
  // Smooth hills[] so the road profile is C2-smooth.  The window has to
  // be WIDER than the keyframe spacing in dense areas (Mercer Island
  // keyframes range 280-610 segs apart) to flatten the keyframe-induced
  // waviness at all.  halfWidth=400 (window=801 segs ≈ 0.5 mi) with 3
  // passes spans 2-3 adjacent keyframes in those dense zones, killing
  // the wave pattern.  Macro features (Snoqualmie 50+ mi, Vantage 10 mi)
  // are far wider than the smoothing window so they survive intact.
  const hills = boxBlurCentered(rawHills, 400, 3);

  // ── Road scale (gradual region-to-region width transition) ───────────
  const rawScales  = new Array(count).fill(1).map((_, i) => getTraitsAt(i / count).roadScale);
  const roadScales = smooth(rawScales, 0.008);

  // Per-segment macro grade — re-derive from the SMOOTHED hills[] (not
  // the raw keyframe elevAt) so grade matches what the renderer actually
  // draws.  Used by the camera pitch lookahead and steep-grade signage.
  const macroGrade   = new Array(count);
  const realGradePct = new Array(count);
  const ftPerSeg = (1 / count) * TOTAL_ROUTE_MILES * 5280;
  for (let i = 0; i < count; i++) {
    const a = hills[i];
    const b = hills[Math.min(count - 1, i + 1)];
    const dY = b - a;                                          // world units
    macroGrade[i]   = dY / SEG_LENGTH;                          // world Y / seg
    realGradePct[i] = ftPerSeg > 0 ? (dY / ELEV_SCALE) / ftPerSeg : 0;
  }
  // Extra polish — symmetric box pass on the grade arrays so signage /
  // physics see a clean curve even where hills[] still has tiny ripples.
  const macroGradeSmooth   = boxBlurCentered(macroGrade,   12, 2);
  const realGradePctSmooth = boxBlurCentered(realGradePct, 12, 2);
  // Photo skyline cutouts are visually distinctive. If the same one
  // repeats within a few nearby placements, it reads as cloned buildings
  // stacked together. Track recent picks per roadside so skyline pools
  // rotate more like a city block instead of using the generic block
  // picker's repeated-primary behavior.
  const recentSkylineKeys = { left: [], right: [] };

  for (let i = 0; i < count; i++) {
    const t      = i / count;
    const traits = getTraitsAt(t);

    const sprites = [];

    // ── Natural scenery ───────────────────────────────────────────────
    // Two-band placement for depth:
    //   • CLOSE band (offset 1.18–1.55) — most common; sits about a lane's
    //     distance from the fog line so the player drives past dense trees.
    //   • FAR  band (offset 1.9–4.5) — spread further out into the scene
    //     so the world has perceived depth instead of a 2-deep tree wall.
    // Each segment can spawn from either band on either side independently.
    // Generic per-segment natural scenery disabled for the current art
    // pass. Individual trees turned into heavy sprite clutter, and after
    // removing trees the remaining shrubs read as repeated piles. Region
    // identity now comes from authored buildings/strips and sparse skyline.

    // (Random brown freeway signs removed — real mileage signs are
    // placed below at each CHECKPOINT location.)

    // ── Buildings (urban regions) ─────────────────────────────────────
    // Two-band placement so cities have depth:
    //   • Frontage band (offset 2.35–3.15) — set back from the sidewalk
    //     by roughly a player-car width so houses do not visually hang
    //     into the roadway at close projection.
    //   • Block-deep band (offset 3.2–5.6) — buildings further into the
    //     city block. Spawns more often than frontage to fill the scene.
    // Generic procedural-style fallback pool (used for regions without a
    // dedicated photo asset set, e.g. palouse).
    // Region-specific Codex building pools.
    //   • West Seattle homes — single-family residences (Pacific NW).
    //   • Seattle/Bellevue towers — downtown Seattle + downtown Bellevue cores.
    //   • Issaquah buildings — late-eastside corridor.
    // Homes ONLY — cranes are spawned exclusively in the bridge stretch
    // (mile 1.0-1.7) by the mile-based branch upstream.  Do not mix
    // CODEX_WEST_SEATTLE_PORT in here or cranes start appearing on
    // residential streets.
    const WEST_SEATTLE_HOMES = [
      'west_seattle_1',
      'west_seattle_2',
      'west_seattle_3',
      'west_seattle_4',
      'west_seattle_5',
      'west_seattle_6',
    ];
    // Resolve the right pool for the current segment based on which
    // I-90 region we're in.  Bellevue skyscrapers only cover the 1.5-mile
    // downtown core, then the corridor steps down to Bellevue/Issaquah
    // mid-rise assets. Eastside flips to Codex Issaquah assets at mile 16.
    const _mileForPool = t * TOTAL_ROUTE_MILES;
    let _regionKeyForPool = null;
    for (const r of REGION_ORDER) {
      if (t >= r.start && t < r.end) { _regionKeyForPool = r.key; break; }
    }
    const buildingPool = (() => {
      switch (_regionKeyForPool) {
        case 'seattle_urban':
        case 'mercer_island':   return WEST_SEATTLE_HOMES;
        case 'downtown_seattle':return CODEX_SEATTLE_SKYLINE;
        case 'eastside_urban':  return CODEX_BELLEVUE_SKYLINE;
        case 'eastside':        return CODEX_ISSAQUAH_BUILDINGS;
        default:                return null;
      }
    })();
    // Treat a homes-only pool as a residential context — the spawner
    // skips procedural houses and drops in image-based homes instead.
    const poolIsHomes = buildingPool === WEST_SEATTLE_HOMES;
    const poolIsCodexSkyline = buildingPool === CODEX_SEATTLE_SKYLINE
                            || buildingPool === CODEX_BELLEVUE_SKYLINE;
    // Block-based texture picker — neighbours share a primary style for
    // ~40-segment runs (≈ a city block) so the eye reads coherent
    // neighbourhoods of similar homes instead of one-of-each chaos.
    // Each block has a "primary" key picked by index; 70 % of buildings
    // in the block use it, 30 % drift to a random other key for variety.
    const pickBuildingTex = (offset = 0) => {
      if (poolIsCodexSkyline) {
        const side = offset < 0 ? 'left' : 'right';
        const recent = recentSkylineKeys[side];
        let choices = buildingPool.filter(key => !recent.includes(key));
        if (choices.length === 0) choices = buildingPool;
        const seed = Math.floor(i / 18) * 5 + (side === 'left' ? 2 : 0);
        const key = choices[seed % choices.length];
        recent.unshift(key);
        recent.length = Math.min(recent.length, Math.min(7, buildingPool.length - 1));
        return key;
      }
      const block      = Math.floor(i / 40);
      const primary    = buildingPool[(block * 7 + 3) % buildingPool.length];
      return rng.bool(0.70)
        ? primary
        : buildingPool[Math.floor(rng.next() * buildingPool.length)];
    };
    const makeBuilding = (offset, style, preTexKey, roadEdgeGapCars) => {
      // Photo-home regions (West Seattle, Mercer Island, Issaquah tail)
      // always spawn image-based residences regardless of the region's
      // declared style — the West Seattle photos are wide-short homes, not
      // towers, so their geometry needs to match.
      // preTexKey lets the fog-line wrapper pick the key first (so it
      // can compute width-aware offset) and pass it back in here without
      // a second RNG roll.
      if (poolIsHomes) {
        return {
          type:      'building',
          texKey:    preTexKey ?? pickBuildingTex(offset),
          offset,
          // Home photos are roughly 1.4× wider than tall — slightly bigger
          // than the procedural-house footprint so they read at full size
          // when the camera is close.
          baseW:     5400 + Math.floor(rng.next() * 2400),
          baseH:     4200 + Math.floor(rng.next() * 1400),
          roadEdgeGapCars,
          collected: false,
        };
      }
      if (style === 'home') {
        return {
          type:      'house',
          offset,
          // 1.5× wider, 2/3 height vs the previous 5× pass — houses
          // now read as wider/shorter ranches/two-stories instead of
          // tall narrow towers.
          baseW:     5200 + Math.floor(rng.next() * 2600),
          baseH:     4600 + Math.floor(rng.next() * 1600),
          wallColor: HOUSE_COLORS[Math.floor(rng.next() * HOUSE_COLORS.length)],
          roofColor: ROOF_COLORS[Math.floor(rng.next() * ROOF_COLORS.length)],
          // Per-house shape rolls.  flatRoof gives modern/contemporary
          // homes a flat roofline instead of the gabled default.
          variant:   rng.next(),
          flatRoof:  rng.bool(0.40),
          hasGarage: rng.bool(0.55),
          hasChimney:rng.bool(0.40),
          hasDormer: rng.bool(0.30),
          twoStory:  rng.bool(0.45),
          roadEdgeGapCars,
          collected: false,
        };
      }
      const isTower = style === 'tower';
      const texKey = preTexKey ?? pickBuildingTex(offset);
      const isCodexSkyline = CODEX_SKYLINE_BACKDROPS.has(texKey);
      const bFloors = isTower
        ? 6 + Math.floor(rng.next() * 12)
        : 3 + Math.floor(rng.next() * 4);
      return {
        type:      'building',
        texKey,
        // Use offset as-given — fog-line spawn math already accounts
        // for setback and the building's half-width.  Previously this
        // clamped codex skyline to CITY_BUILDING_SETBACK (5.35), which
        // overrode the spawn-time decision; removed so fog-line wins.
        offset,
        // Per user: everything but weapons/drugs should be collidable.
        // (Default undefined → solid obstacle in the scenery collision
        // check at GameScene.js:2914.  Pickups aren't in SCENERY_TYPES
        // so they're unaffected and still pick up normally.)
        collidable: undefined,
        heightBoost: isCodexSkyline ? 3.0 : undefined,
        baseW:     isTower
          ? 900 + Math.floor(rng.next() * 700)
          : 700 + Math.floor(rng.next() * 500),
        baseH:     2200 + bFloors * 1100,
        wallColor: TOWER_COLORS[Math.floor(rng.next() * TOWER_COLORS.length)],
        floors:    bFloors,
        collected: false,
      };
    };
    // ── Fog-line wrapper for makeBuilding ──────────────────────────────
    // Take a "side + car-widths past the fog line" pair and resolve it
    // to the absolute center offset makeBuilding expects.  Picks the
    // texKey FIRST so the half-width math can use the correct asset
    // profile, then passes that pre-picked key into makeBuilding so
    // the texture choice doesn't drift between the two calls (which
    // would also burn extra RNG on the pickBuildingTex path).
    //
    // Why: see fogLineOffset() block comment up top.  Procedural
    // 'home' / tower paths have no texKey at all, so they use the
    // default sizeMult fallback in fogLineOffset.
    const makeBuildingAtFog = (sign, carWidthsPastFog, style) => {
      // A throwaway sign-only offset is used only to drive the
      // skyline texture rotator (which keys off the offset's sign).
      const sideHint = sign >= 0 ? +CITY_BUILDING_SETBACK : -CITY_BUILDING_SETBACK;
      const texKey   = (poolIsHomes || style !== 'home')
        ? pickBuildingTex(sideHint)
        : null;
      const off = fogLineOffset(texKey, sign, carWidthsPastFog);
      const isResidentialFrontage = poolIsHomes || style === 'home'
        || _regionKeyForPool === 'eastside';
      return makeBuilding(
        off,
        style,
        texKey ?? undefined,
        isResidentialFrontage ? carWidthsPastFog : undefined,
      );
    };
    // Hard cap: no buildings past mile 17 (Issaquah onward).  Player
    // wants the suburbs/cities to taper out into open road from there.
    // Bellevue tail (mile 14-17) — Bellevue's east half is mostly
    // wooded foothill leading into Issaquah; thin out density so the
    // city dissolves naturally rather than ending abruptly at mile 17.
    const mileNow = t * TOTAL_ROUTE_MILES;
    let densityScale = 1.0;
    if (mileNow > 14 && mileNow <= 17) {
      // Linear taper 1.0 → 0.15 over miles 14-17.
      densityScale = 1.0 - 0.85 * ((mileNow - 14) / 3);
    }
    // ── West Seattle approach (mile 0-1) ────────────────────────────
    // Water on the LEFT (rendered in Road.js via seg.waterLeft).
    // RIGHT side: pseudo-random walk through the home pool so the same
    // 6 PNGs combine differently every block — no obvious repeat
    // patterns.  No left spawns at all (the bay is over there).
    if (mileNow >= 0 && mileNow < 1.0) {
      const slotsPerMile = 100;  // dense residential frontage
      const segsPerSlot  = (ROUTE_SEGS / TOTAL_ROUTE_MILES) / slotsPerMile;
      const slotNow  = Math.floor(i / segsPerSlot);
      const slotPrev = i > 0 ? Math.floor((i - 1) / segsPerSlot) : -1;
      if (slotNow > slotPrev) {
        // Spawn at every slot — no random skips.  (Previously had a
        // 15% skip for "natural gaps" but the gaps left visible holes
        // in the home row as the player drove past, and the user wants
        // an unbroken West Seattle frontage from start to bridge.)
        // Pseudo-random texture pick — a hash of slot index gives a
        // non-repeating but deterministic walk through the home pool.
        const hash    = (slotNow * 7919 + 13) % 997;
        const texKey  = WEST_SEATTLE_HOMES[hash % WEST_SEATTLE_HOMES.length];
        // Right side only — water field on left, no spawns there.
        // Positive offset = RIGHT in this engine's coords.
        // Choose the permanent center offset from a one-and-a-quarter car
        // width street-facing setback. GameScene renders this fixed position.
        const offset  = fogLineOffset(texKey, +1, RESIDENTIAL_FRONTAGE_GAP_CARS);
        sprites.push({
          type:      'building',
          texKey,
          offset:    offset,
          baseW:     5400 + Math.floor(rng.next() * 2400),
          baseH:     4200 + Math.floor(rng.next() * 1400),
          roadEdgeGapCars: RESIDENTIAL_FRONTAGE_GAP_CARS,
          collected: false,
        });
      }
    }
    // ── West Seattle Bridge cranes (mile 1.05 – 1.70) ──────────────
    // Container cranes sit in paved port yards beside the elevated bridge.
    // Two short channel intervals beneath the bridge remain free of cranes.
    // Visibility lookahead = DRAW_DIST × SEG_LENGTH ÷ (ROUTE_SEGS /
    // TOTAL_ROUTE_MILES) ≈ 0.23 mi, so spawn at 1.05 yields first
    // visible at ~0.82 mi.  Start pulled back another ~0.07 mi
    // (~2 sec) per user request so cranes appear earlier still.
    // GameScene._renderSceneSprites() caps the crane lookahead at
    // DRAW_DIST explicitly (cranes don't render beyond the road-
    // projection cache) so cranes never appear with the wrong
    // perspective at extreme distance.
    else if (mileNow >= 1.05 && mileNow < WEST_SEATTLE_BRIDGE_RANGE[1]) {
      const CRANE_LEFT_POOL = [
        'codex_ws_crane_crate_left',
        'codex_ws_crane_white_boxes_left',
      ];
      const CRANE_RIGHT_POOL = [
        'codex_ws_crane_crate_right',
        'codex_ws_crane_white_boxes_right',
      ];
      // 7 slots/mi × 0.65 mi bridge × ~0.55 prob × 2 sides ≈ 5-8 cranes
      // total — reads as a port row, not a stacked junkyard.
      const craneSlotsPerMile = 7;
      const segsPerCraneSlot  = (ROUTE_SEGS / TOTAL_ROUTE_MILES) / craneSlotsPerMile;
      const craneSlot      = Math.floor(i / segsPerCraneSlot);
      const craneSlotPrev  = i > 0 ? Math.floor((i - 1) / segsPerCraneSlot) : -1;
      const onPortWaterChannel = WEST_SEATTLE_WATER_CHANNEL_RANGES.some(
        ([start, end]) => mileNow >= start && mileNow < end
      );
      if (!onPortWaterChannel && craneSlot > craneSlotPrev) {
        const craneKeyL = CRANE_LEFT_POOL[ craneSlot       % CRANE_LEFT_POOL.length ];
        const craneKeyR = CRANE_RIGHT_POOL[(craneSlot + 2) % CRANE_RIGHT_POOL.length];
        // Sit far off the bridge on port flats below — pushed well
        // outward (world-space, not pixel-space) so their footprints
        // never overlap the road area.
        const craneOff  = 12.0 + rng.next() * 2.5;
        // The bridge deck is repainted at depth 4 in Road.js. Keeping
        // cranes at depth 2 puts their bases behind that opaque deck so
        // the player never sees a crane through the roadway.
        if (rng.bool(0.55)) sprites.push({
          type: 'building', texKey: craneKeyL,
          offset: -(craneOff),    // LEFT side
          baseW: 900, baseH: 2400, collected: false,
          renderDepth: 2,
        });
        if (rng.bool(0.55)) sprites.push({
          type: 'building', texKey: craneKeyR,
          offset: +(craneOff),    // RIGHT side
          baseW: 900, baseH: 2400, collected: false,
          renderDepth: 2,
        });
      }
    }
    // Eastside continues with sparse suburban / freeway-edge structures
    // after Bellevue instead of turning into a blank green field.
    else if (traits.buildings && buildingPool && mileNow <= 17) {
      const style = traits.buildingStyle || 'midrise';

      // ── Per-region full pool — each city cycles through its whole
      //    texture array so the player sees the entire variety as they
      //    drive through ("add a building passing every 1/20 mi").
      // Separate per-side cycle pools so each side gets directional
      // variants where they exist.  Flat-front bases are gone — only
      // the angle-matched _left / _right images are still in the
      // manifest, so the left pool references _left keys, the right
      // pool references _right keys.  Buildings with no directional
      // pair (skyline, wavy_residential, etc.) appear in both pools.
      const BELLEVUE_LEFT_POOL = [
        'codex_bellevue_skyline',
        'codex_pse_bellevue_office_left',
        'codex_pse_bellevue_second_office_left',
        'codex_bellevue_wavy_residential',
        'codex_bellevue_city_center_dark',
        'codex_bellevue_braced_glass_tower',
        'codex_bellevue_twin_residential_left',
        'codex_bellevue_residential_cluster',
      ];
      const BELLEVUE_RIGHT_POOL = [
        'codex_bellevue_skyline',
        'codex_pse_bellevue_office_right',
        'codex_pse_bellevue_second_office_right',
        'codex_bellevue_wavy_residential',
        'codex_bellevue_city_center_dark',
        'codex_bellevue_braced_glass_tower',
        // twin_residential has no _right variant yet — use the
        // residential_cluster as substitute so the right pool isn't
        // a one-short cycle.
        'codex_bellevue_residential_cluster',
        'codex_bellevue_residential_cluster',
      ];
      const CYCLE_POOLS = {
        seattle_urban:    { left: WEST_SEATTLE_HOMES,    right: WEST_SEATTLE_HOMES    },
        mercer_island:    { left: WEST_SEATTLE_HOMES,    right: WEST_SEATTLE_HOMES    },
        downtown_seattle: { left: CODEX_SEATTLE_SKYLINE, right: CODEX_SEATTLE_SKYLINE },
        eastside_urban:   { left: BELLEVUE_LEFT_POOL,    right: BELLEVUE_RIGHT_POOL   },
        eastside:         { left: CODEX_ISSAQUAH_BUILDINGS, right: CODEX_ISSAQUAH_BUILDINGS },
      };
      const cyclePool = CYCLE_POOLS[_regionKeyForPool];

      // The Bellevue approach strip is drawn as an opaque distant layer
      // in GameScene; these grounded sprites are the close drive-by,
      // collidable city frontage.

      // ── Cycle spawn — buildings appear at regular intervals along
      //    the road, alternating left and right with directional
      //    variants where they exist. West Seattle retains dense home
      //    frontage; Mercer is forest-only and skips building spawn;
      //    skyline regions stay at one placement per ~1/20 mi per side.
      //
      // Mile 0–1.05 (West Seattle approach + the bridge on-ramp gap
      // before the crane block at 1.05) has Elliott Bay on the LEFT,
      // so the cycle spawn must not drop homes there.  Range extends
      // through 1.05 because from mile 0 the camera can see ~0.6 mi
      // forward, easily reaching the bridge on-ramp slot — a left-side
      // home spawned there reads as floating in the bay.
      const inWestSeattleApproach = (mileNow >= 0 && mileNow < 1.05);
      const isMercerForestOnly = _regionKeyForPool === 'mercer_island';
      if (!inWestSeattleApproach && !isMercerForestOnly
          && cyclePool && cyclePool.left.length > 0 && densityScale > 0.2) {
        // Mercer intentionally bypasses this block: its roadside lots are
        // filled with reusable tree sprites below instead of houses.
        const slotsPerMile  = poolIsHomes ? 80 : 20;
        const segsPerSlot   = (ROUTE_SEGS / TOTAL_ROUTE_MILES) / slotsPerMile;
        const slotNow  = Math.floor(i / segsPerSlot);
        const slotPrev = i > 0 ? Math.floor((i - 1) / segsPerSlot) : -1;
        if (slotNow > slotPrev) {
          // Vacant lots, parks, and side streets keep dense frontage from
          // feeling like a checkerboard wall of buildings.
          const skipSlot = rng.bool(0.20);
          if (!skipSlot) {
            // Each side cycles its own pool independently so directional
            // variants line up with the side they're spawned on.
            const leftKey  = cyclePool.left[slotNow % cyclePool.left.length];
            const rightKey = cyclePool.right[(slotNow + 3) % cyclePool.right.length];
            // Per-region "car-widths past the fog line" gaps — see
            // fogLineOffset() block comment near the top of this file.
            //
            //   • West Seattle homes: 1.25 — tight residential frontage,
            //     RIGHT SIDE ONLY (water on left), so the row only
            //     hems in one peripheral.
            //   • Issaquah homes: 1.25 — single-sided frontage like
            //     West Seattle, keep tight.
            //   • Bellevue skyline + downtown Seattle skyline: 4.0 — tall
            //     wide cluster art needs the city block of buffer the
            //     old CITY_BUILDING_SETBACK provided, but expressed now
            //     in fog-line units instead of an absolute number.
            //
            // Skyline rows retain small jitter; residential frontage is
            // fixed so a row of homes stays parallel to the fog line.
            const carWidthsPastFog = (() => {
              switch (_regionKeyForPool) {
                case 'seattle_urban':    return RESIDENTIAL_FRONTAGE_GAP_CARS;
                case 'downtown_seattle': return 4.00;   // skyline, unchanged
                case 'eastside_urban':   return 4.00;   // skyline, unchanged
                case 'eastside':         return RESIDENTIAL_FRONTAGE_GAP_CARS;
                default:                 return 0.90;   // was 0.60
              }
            })();
            const makeOne  = (sign, texKey, rampClearance) => {
              const isResidentialFrontage = poolIsHomes || _regionKeyForPool === 'eastside';
              const gapCars = isResidentialFrontage
                ? carWidthsPastFog
                : carWidthsPastFog + rng.next() * 0.25;
              const off  = fogLineOffset(texKey, sign, gapCars);
              const isCodexSkyline = CODEX_SKYLINE_BACKDROPS.has(texKey);
              sprites.push({
                type:      'building',
                texKey,
                offset:    off,
                baseW:     poolIsHomes ? (5400 + Math.floor(rng.next() * 2400))
                                       : (800  + Math.floor(rng.next() * 500)),
                baseH:     poolIsHomes ? (4200 + Math.floor(rng.next() * 1400))
                                       : (2200 + Math.floor(rng.next() * 1500)),
                roadEdgeGapCars: isResidentialFrontage ? gapCars : undefined,
                collected: false,
                // visualMinOffset intentionally omitted — fog-line
                // spawn (off = fogLineOffset(...)) already places this
                // sprite at the correct setback for its asset width.
                // Forcing CITY_BUILDING_SETBACK here would override the
                // per-region car-widths-past-fog math the spawn just
                // ran.
                // rampClearance tells the renderer to push this sprite
                // PAST the off-ramp's outer edge so the house sits on
                // the far side of the ramp, not in the gore wedge.
                rampClearance:   rampClearance || undefined,
                // Explicit collidable: true per user spec — every
                // cycle-spawned building is a solid obstacle.
                collidable:      true,
                heightBoost:     isCodexSkyline ? 3.0                    : undefined,
              });
            };
            // Both sides spawn together (single decision for the pair).
            // Previously each side rolled 0.90 independently, so 19% of
            // slots had only one side populated — the asymmetry read as
            // "houses appear on the left before the right" as the player
            // approached.  Slot-level skip (rng.bool(0.20) above) still
            // creates natural vacant lots, but per-slot the pair stays
            // symmetric.
            // RAMP GUARD: ramps from rest stops widen the right shoulder
            // over 1 mi before the exit + 0.3 mi after.  A right-side
            // house spawned in that window sits in the gore wedge
            // between the road and the ramp.  Detection by checking
            // each segment's rampStrength FAILS here — rampStrength is
            // written AFTER the building spawn loop runs, so it's all
            // zero at this point.  Instead, check the spawn's mile
            // directly against REST_STOPS mileages: any house spawning
            // within (rs.mileage - 1.0, rs.mileage + 0.3) gets
            // rampClearance set, and the renderer pushes it past the
            // ramp's outer edge.  Left side is unaffected.
            const onRamp = REST_STOPS.some(rs =>
              mileNow >= rs.mileage - 1.0 && mileNow <= rs.mileage + 0.3
            );
            // Sign convention: positive offset = screen-right (per
            // Road.js sampleSurface: sx += screenW * laneOffset).  So
            // sign=-1 puts the leftKey textures on the LEFT side, and
            // sign=+1 puts the rightKey textures on the RIGHT side
            // (where the off-ramp also opens, so it carries the
            // rampClearance push).  Previously these were swapped,
            // which placed *_left directional facades on the right
            // side of the road for Bellevue.
            makeOne(-1, leftKey,  false);
            makeOne( 1, rightKey, onRamp);
          }
        }
      }
      // ── Legacy dense placement — runs ONLY for non-city regions
      //    (rural cascades / palouse / etc).  City regions use the
      //    layered strip + cycle approach above.
      if (!cyclePool) {
        if (poolIsHomes) {
        // ── Neighborhood-block placement ────────────────────────────
        // Homes don't read as "a neighborhood" when each segment rolls
        // independently — you get a sprinkle of houses with random gaps.
        // Group them into ~50-segment blocks (≈ a real residential block)
        // where 70% of blocks are dense rows of homes and 30% are gaps
        // (parks / cul-de-sacs / vacant lots).  Within a block, both
        // sides share roughly the same setback so homes line up like a
        // planned subdivision instead of zig-zagging.
        //
        // Why fog-line model: previously each row used an absolute
        // center offset (`blockSetback ≈ 2.45–3.05`).  That centered a
        // skinny house and a wide cluster at the same place, so wider
        // assets ended up with their NEAR edge in the road.  Now we
        // pick "car-widths past the fog line" for each row depth and
        // the helper adds back the asset's half-width.
        const block        = Math.floor(i / 50);
        const blockHash    = (block * 7919 + 13) % 100;
        const blockHasHomes= blockHash < 70;
        const blockMul     = blockHasHomes ? 1.6 : 0.10;
        // Per-block gap variance (0.0–0.6 car-widths) so adjacent
        // blocks don't all sit at identical setback.
        const blockGapJ    = ((block * 1117 + 5) % 60) / 100;
        const jitterCW     = () => (rng.next() - 0.5) * 0.30;  // ±0.15 car-widths
        // Front row was 0.60 — bumped to 0.90 per user "30-50 px off
        // the road" feedback.  Deep + back rows track the front so the
        // subdivision still reads as parallel streets.
        const frontGap     = 0.90 + blockGapJ;                 // procedural-homes front row
        const deepGap      = frontGap + 3.0;                   // ~1.4 normalized units back
        const backGap      = frontGap + 6.5;                   // ~3.0 normalized units back
        const frontP       = traits.buildingDensity * 0.30 * densityScale * blockMul;
        if (rng.bool(frontP)) sprites.push(makeBuildingAtFog( +1, frontGap + jitterCW(), style));
        if (rng.bool(frontP)) sprites.push(makeBuildingAtFog( -1, frontGap + jitterCW(), style));
        // Second-row homes — typical of a subdivision with parallel
        // streets behind the frontage.  Half the rate so the back row
        // reads as sparser depth fill, not a doubled wall.
        const deepP = traits.buildingDensity * 0.35 * densityScale * blockMul;
        if (rng.bool(deepP)) sprites.push(makeBuildingAtFog( +1, deepGap + jitterCW(), style));
        if (rng.bool(deepP)) sprites.push(makeBuildingAtFog( -1, deepGap + jitterCW(), style));
        // Far-back row — homes way out at the edge of perception.  Cheap
        // pseudo-3D depth: each segment is just a few extra rng.bool()
        // rolls + sprite slots, no per-frame cost.  Quarter rate so the
        // distance reads as dotted houses on the horizon, not another wall.
        const backP = traits.buildingDensity * 0.18 * densityScale * blockMul;
        if (rng.bool(backP)) sprites.push(makeBuildingAtFog( +1, backGap + jitterCW(), style));
        if (rng.bool(backP)) sprites.push(makeBuildingAtFog( -1, backGap + jitterCW(), style));
      } else {
        if (poolIsCodexSkyline) {
          // City photo clusters should feel roadside, but not glued to
          // the sidewalk.  Front row sits ~4 car-widths past the fog
          // line (skyline-region default); back row adds another ~3.5
          // car-widths of depth for the layered city look.
          const skylineP = Math.min(0.034, traits.buildingDensity * 0.20) * densityScale * 0.25;
          if (rng.bool(skylineP)) sprites.push(makeBuildingAtFog( +1, 4.0 + rng.next() * 1.5, style));
          if (rng.bool(skylineP)) sprites.push(makeBuildingAtFog( -1, 4.0 + rng.next() * 1.5, style));
        } else {
          // Generic tower / midrise placement — front row at ~0.9
          // car-widths past the fog line (was 0.6; bumped per user
          // "30-50 px off the road" feedback), deep row a few car-widths
          // back.
          const frontageP = traits.buildingDensity * 0.30 * densityScale;
          if (rng.bool(frontageP)) sprites.push(makeBuildingAtFog( +1, 0.90 + rng.next() * 0.50, style));
          if (rng.bool(frontageP)) sprites.push(makeBuildingAtFog( -1, 0.90 + rng.next() * 0.50, style));
          const deepP = traits.buildingDensity * 0.70 * densityScale;
          if (rng.bool(deepP)) sprites.push(makeBuildingAtFog( +1, 2.5 + rng.next() * 3.0, style));
          if (rng.bool(deepP)) sprites.push(makeBuildingAtFog( -1, 2.5 + rng.next() * 3.0, style));
        }
        }
      }
    }
    // ── Regional trees & shrubs ───────────────────────────────────────
    // Slot-based spawn (deterministic, mirrors the building cycle):
    // each side independently picks a tree from the region pool every
    // N segments.  Density and species pool depend on the current
    // region.  Bridges / tunnels / water flags strip these out in the
    // post-pass below (same path that strips other non-collectible
    // sprites from those zones).
    let _treePool = null;
    let _treeSlotsPerMile = 0;
    let _shrubPool = null;
    let _shrubSlotsPerMile = 0;
    let _denseStreetTrees = false;
    let _treeHeightBoost = 1;       // base per-spawn vertical scale, 1 = native
    let _treeBigBoostChance = 0;    // probability a given tree spawns much taller
    let _treeBigBoostMin = 2;       // min boost for the "big" variant
    let _treeBigBoostMax = 3;       // max boost for the "big" variant
    switch (_regionKeyForPool) {
      case 'seattle_urban':
        // West Seattle homes — maples & conifers between the house row
        // and the road.  Suppressed during the dense home frontage
        // (mile 0–1.05) by the guard below; spawns elsewhere if the
        // region runs past that window.
        _treePool = SEATTLE_STREET_TREES;
        _treeSlotsPerMile = 100;
        _denseStreetTrees = true;
        break;
      case 'downtown_seattle':
        // SoDo → downtown Seattle.  Tree-lined surface streets,
        // approach to the Mercer Island floating bridge.  User asked
        // for ~5× the trees and bigger/taller, so bumped from 120 →
        // 600 slots/mile and added a 1.5× heightBoost on each spawn.
        // Heavily deciduous SEATTLE_STREET_TREES pool.  Trees co-
        // exist with the regional building spawn — separate sprite
        // type written by SPAWN_TREE, not part of the building if/
        // else chain.
        _treePool = SEATTLE_STREET_TREES;
        _treeSlotsPerMile = 600;
        _treeHeightBoost  = 1.5;
        _denseStreetTrees = true;
        break;
      case 'mercer_island':
        // Suburban island — continuous mixed mature canopy.  User
        // wants way more trees with height variation: bumped 60 → 400
        // slots/mile (was 300) and 35% of spawns get a 2-3× boost so
        // tall giants are sprinkled among the curb row.  A separate
        // outer-row spawn below ALSO drops tall giants at offset
        // 3.5-5.5 (deeper into the wooded yard) so the canopy reads
        // as multi-layered, not a single flat ribbon.
        _treePool = MERCER_ISLAND_TREES;
        _treeSlotsPerMile = 400;
        _denseStreetTrees = true;
        _treeBigBoostChance = 0.35;
        _treeBigBoostMin    = 2.0;
        _treeBigBoostMax    = 3.0;
        break;
      case 'eastside_urban':
        // Bellevue downtown — buildings dominate but the city has heavy
        // street-tree planting.  With buildings at ~20 slots/mile, 150
        // paired tree slots/mile gives each building interval a planted
        // run of roughly 7-8 maples per side rather than occasional props.
        _treePool = BELLEVUE_STREET_TREES;
        _treeSlotsPerMile = 150;
        _denseStreetTrees = true;
        break;
      case 'eastside':
        // Bellevue tail → Issaquah → North Bend — dense roadside
        // conifers, the iconic I-90 wooded eastside stretch.
        _treePool = WESTERN_WA_CONIFERS;
        _treeSlotsPerMile = 22;
        break;
      case 'cascades':
        // Snoqualmie Pass + Cle Elum — heaviest forest on the route.
        _treePool = WESTERN_WA_CONIFERS;
        _treeSlotsPerMile = 30;
        break;
      case 'east_cascades':
        // Cle Elum → Ellensburg → Vantage — sparser, drier; pines
        // start replacing the wet-side conifers.
        _treePool = EAST_CASCADES_PINES;
        _treeSlotsPerMile = 12;
        break;
      case 'columbia_basin':
        // High desert — sage steppe, sparse ponderosa.
        _treePool = COLUMBIA_BASIN_SPARSE_PINES;
        _treeSlotsPerMile = 3;
        _shrubPool = COLUMBIA_BASIN_SHRUBS;
        _shrubSlotsPerMile = 18;
        break;
      // palouse: wheat country — no roadside trees, occasional
      // farmstead shelterbelt only.  Skip the spawn entirely.
    }
    if (_treePool || _shrubPool) {
      // Suppress spawning inside the urban West Seattle approach (the
      // dense home frontage already fills both sides) and on the bridge
      // / over-water stretches (their post-pass strips non-collectibles
      // anyway, but no point creating sprites we'll just throw away).
      const _suppressTrees =
        (mileNow >= 0 && mileNow < 1.05) ||              // West Seattle approach
        traits.water === true;                            // floating bridges
      if (!_suppressTrees) {
        const SPAWN_TREE = (pool, slotsPerMile, kind /* 'tree' | 'shrub' */) => {
          if (!pool || slotsPerMile <= 0) return;
          const isDenseStreetRow = kind === 'tree' && _denseStreetTrees;
          const segsPerSlot = (ROUTE_SEGS / TOTAL_ROUTE_MILES) / slotsPerMile;
          const slotNow  = Math.floor(i / segsPerSlot);
          const slotPrev = i > 0 ? Math.floor((i - 1) / segsPerSlot) : -1;
          if (slotNow <= slotPrev) return;
          // ~15% slot skip — natural gaps between clusters so the row
          // doesn't look like a procedural picket fence. Bellevue's
          // landscaped street row intentionally stays continuous.
          if (!isDenseStreetRow && rng.bool(0.15)) return;
          // Each side picks its own variant.  Offset jitter: trees sit
          // 1.85–2.6 from centerline (just past the rumble strip);
          // shrubs sit slightly closer (1.55–2.2).
          const baseMin = kind === 'shrub' ? 1.55 : 1.85;
          const baseMax = kind === 'shrub' ? 2.20 : 2.60;
          const leftKey  = pool[ slotNow       % pool.length];
          const rightKey = pool[(slotNow + 1)  % pool.length];
          const pushOne = (sign, texKey) => {
            const off = sign * (baseMin + rng.next() * (baseMax - baseMin));
            // Per-spawn height boost.  Three layers:
            //   1. Regional base boost (_treeHeightBoost, e.g. 1.5 in
            //      downtown Seattle for mature street trees)
            //   2. Random "giant" variant — rolls _treeBigBoostChance,
            //      if hit picks a heightBoost in [Min, Max] so a few
            //      trees per region tower over the rest
            //   3. Fallback: undefined (renderer treats as 1.0)
            let boost = _treeHeightBoost;
            if (kind === 'tree' && _treeBigBoostChance > 0
                && rng.next() < _treeBigBoostChance) {
              boost = _treeBigBoostMin
                    + rng.next() * (_treeBigBoostMax - _treeBigBoostMin);
            }
            sprites.push({
              type:      kind,
              texKey,
              offset:    off,
              baseW:     1500,  // overwritten by texture.width at render
              baseH:     2400,  // overwritten by texture.height at render
              collected: false,
              // Trees are solid obstacles but light damage — much less
              // punishing than buildings/scenery (10 HP) so the wooded
              // eastside isn't a meat grinder.  GameScene reads `damage`
              // off the sprite in _triggerSceneryRespawn.
              damage:    5,
              heightBoost: (kind === 'tree' && boost !== 1) ? boost : undefined,
            });
          };
          // Wild forest rows keep some asymmetry. Bellevue is deliberately
          // planted on both curbs so buildings read as tree-lined blocks.
          const bothSides = isDenseStreetRow || rng.bool(0.75);
          pushOne( 1, leftKey);
          if (bothSides) pushOne(-1, rightKey);
        };
        SPAWN_TREE(_treePool,  _treeSlotsPerMile,  'tree');
        SPAWN_TREE(_shrubPool, _shrubSlotsPerMile, 'shrub');
      }
    }

    // ── Mercer wooded lots ─────────────────────────────────────────────
    // Reuse the loaded tree textures and existing scene-sprite pool rather
    // than adding forest bitmap assets or allocating a second render pool.
    // These deeper trees supply dense canopy behind the curbside row; the
    // curbside row above remains the only collision-relevant tree layer.
    const _inMercerForestLots =
      _regionKeyForPool === 'mercer_island'
      && mileNow >= 7.30 && mileNow < 9.70
      && !(mileNow >= MERCER_LID_TUNNEL_RANGE[0] && mileNow < MERCER_LID_TUNNEL_RANGE[1]);
    if (_inMercerForestLots) {
      // Bumped 72 → 130 slots/mi for noticeably denser canopy.
      const FOREST_SLOTS_PER_MILE = 130;
      const segsPerForestSlot = (ROUTE_SEGS / TOTAL_ROUTE_MILES) / FOREST_SLOTS_PER_MILE;
      const forestSlotNow  = Math.floor(i / segsPerForestSlot);
      const forestSlotPrev = i > 0 ? Math.floor((i - 1) / segsPerForestSlot) : -1;
      if (forestSlotNow > forestSlotPrev) {
        // Outer rows scale up (bigger trees the further from the road)
        // so the silhouette behind the curbside row reads as mature
        // forest receding to a tall back wall.  bigChance gives a
        // sprinkle of 2-3× giants in the outer two rows.
        const LOT_ROWS = [
          { min: 3.00, max: 4.25, keep: 0.85, scale: 1.10, bigChance: 0.00 },
          { min: 4.80, max: 6.40, keep: 0.95, scale: 1.55, bigChance: 0.20 },
          { min: 6.70, max: 9.00, keep: 0.80, scale: 2.10, bigChance: 0.30 },
        ];
        let speciesOffset = 0;
        for (const row of LOT_ROWS) {
          for (const sign of [-1, 1]) {
            if (!rng.bool(row.keep)) continue;
            const key = MERCER_ISLAND_TREES[
              (forestSlotNow + speciesOffset++) % MERCER_ISLAND_TREES.length
            ];
            const big = row.bigChance > 0 && rng.next() < row.bigChance;
            const boost = big
              ? (2.0 + rng.next() * 1.0)        // 2-3× giants
              : row.scale * (0.92 + rng.next() * 0.18);
            sprites.push({
              type:        'tree',
              texKey:      key,
              offset:      sign * (row.min + rng.next() * (row.max - row.min)),
              baseW:       1500,
              baseH:       2400,
              collected:   false,
              collidable:  false,
              flipX:       rng.bool(0.45),
              heightBoost: boost,
            });
          }
        }
      }
    }

    // ── DENSE FOREST overlay: North Bend (30–40) + Snoqualmie Pass
    //    (40–60) ─────────────────────────────────────────────────────────
    // Drops hundreds of conifers per visible window so those zones read
    // as wall-of-trees PNW forest instead of sparse roadside.  Spawned
    // in FOUR parallel rows at increasing offsets so the trees span
    // from the road shoulder all the way to the screen border.  Each
    // sprite gets:
    //   • random texKey from a 5-PNG conifer pool
    //   • 45 % chance flipped horizontally
    //   • random sizeMult 1.4–2.6 for varied silhouettes
    //   • collidable ONLY when offset < 3.0 (player only crashes into
    //     trees they could plausibly drift into; far ones are visual)
    const _inDenseForest = (mileNow >= 30 && mileNow < 60);
    if (_inDenseForest && !traits.water) {
      const DENSE_FOREST_POOL = [
        'tree_douglas_fir_1', 'tree_red_cedar_1',
        'tree_hemlock1',      'tree_hemlock2', 'tree_cedar1',
      ];
      // 200 slots/mile per row × 4 rows × 2 sides ≈ 1600 spawn ROLLS
      // per mile; with 30 % keep rate ≈ 480 trees/mile actually pushed.
      // Visible window ~0.24 mi → ~115 trees per frame from this pass
      // alone, on top of the baseline tree spawn above.
      const DENSE_SLOTS_PER_MILE = 200;
      const segsPerSlot = (ROUTE_SEGS / TOTAL_ROUTE_MILES) / DENSE_SLOTS_PER_MILE;
      const slotNow  = Math.floor(i / segsPerSlot);
      const slotPrev = i > 0 ? Math.floor((i - 1) / segsPerSlot) : -1;
      if (slotNow > slotPrev) {
        // Skip the close rows on this side when the segment is part of
        // a rest-stop off-ramp window — exit ramps open on the RIGHT
        // for ~1 mi before each stop.  Without this, trees would spawn
        // on the painted exit asphalt.  Far rows still spawn (they're
        // past the ramp's outer edge ~4.3 either way).
        const _segOnRamp = REST_STOPS.some(rs =>
          mileNow >= rs.mileage - 1.0 && mileNow <= rs.mileage + 0.3
        );
        // Four parallel rows: trees push TIGHT to the road shoulder
        // (close row sits 1.10–1.50 — just past the fog line at ±1.0,
        // so trees feel "almost right off the roadway" per spec).
        // Rows step outward to span border-to-border.
        const ROWS = [
          { min: 1.10, max: 1.50, keep: 0.55, closeRow: true  },   // shoulder edge
          { min: 1.80, max: 2.70, keep: 0.55, closeRow: true  },   // mid-close
          { min: 3.20, max: 4.80, keep: 0.45, closeRow: false },   // mid-far
          { min: 5.50, max: 9.00, keep: 0.30, closeRow: false },   // far horizon
        ];
        for (const row of ROWS) {
          for (const sign of [-1, 1]) {
            // Right-side close rows are suppressed during ramp windows
            // so the off-ramp asphalt stays clear.  Trees can sit just
            // past the ramp's outer edge via the far rows.
            if (row.closeRow && sign === 1 && _segOnRamp) continue;
            if (!rng.bool(row.keep)) continue;
            const key = DENSE_FOREST_POOL[
              Math.floor(rng.next() * DENSE_FOREST_POOL.length)
            ];
            const off  = sign * (row.min + rng.next() * (row.max - row.min));
            const flip = rng.bool(0.45);
            // sizeMult 1.4–2.6 — bigger for closer rows, smaller for far.
            const sizeMult = 1.4 + rng.next() * 1.2;
            sprites.push({
              type:        'tree',
              texKey:      key,
              offset:      off,
              baseW:       1500,
              baseH:       2400,
              collected:   false,
              flipX:       flip,
              sizeMult,
              damage:      5,
              // Far rows are pure visual filler — non-collidable so
              // the player isn't pinged when drifting 4+ units sideways.
              collidable:  Math.abs(off) < 3.0 ? undefined : false,
            });
          }
        }
      }
    }

    // ── Drug collectibles (density varies by region) ─────────────────
    // type starts as 'drug-pending' so the actual drug is chosen at runtime
    // by DrugSystem.chooseAddictedDrug(...) when the sprite enters the visible
    // window. That lets per-player addiction skew which drug actually shows up.
    if (rng.bool(traits.drugDensity ?? 0.020)) {
      sprites.push({
        type:            'drug-pending',
        defaultType:     pickCollectible(rng, t),
        offset:          rng.range(-0.55, 0.55),
        baseW: 720, baseH: 880,   // 2× per request — much easier to spot
        collected:       false,
        isCollectible:   true,
        collectibleType: 'drug',
        // Stable per-sprite roll so 4★+ suppression (~40% of drugs disappear)
        // is deterministic — same spot suppressed every time the player
        // re-enters that segment at high heat.
        lootSeed:        rng.next(),
      });
    }

    // ── F12 weapon tokens ─────────────────────────────────────────────
    // Spaced ~every 1,200 segments (≈ 9 sec at top speed) so they're
    // tactical pickups, not spam.
    if (i % 1200 === 77) {
      const f12Type = pickF12(rng);
      const f12TexMap = {
        f12_gun:    'weapon_gun',
        f12_spike:  'weapon_spike_strip',
        f12_paint:  'weapon_paint_bomb',
        f12_rocket: 'weapon_rocket',     // procedural placeholder if PNG missing
      };
      sprites.push({
        type:            f12Type,
        texKey:          f12TexMap[f12Type],
        offset:          rng.range(-0.45, 0.45),
        baseW: 720, baseH: 880,   // same as drug pickups so they appear similar size
        collected:       false,
        isCollectible:   true,
        collectibleType: 'f12',
      });
    }

    // ── Cop roadblock ─────────────────────────────────────────────────
    if (i > 300 && i % 240 === 133 && t > 0.05) {
      sprites.push({
        type:            'cop_roadblock',
        offset:          (rng.bool() ? 0.12 : -0.12),
        baseW: 800, baseH: 420,  // big and unmissable
        collected:       false,
        isCollectible:   true,
        collectibleType: 'cop_roadblock',
      });
    }

    // Hitchhikers used to spawn 0.6 %/segment everywhere on the open
    // highway, which made Tap-mode players inadvertently brush them
    // along the constantly-left-pulling shoulder.  They now ONLY appear
    // at on/off-ramps near each rest stop — see the rest-stop loop
    // below where they're seeded into the ramp window.

    segments.push({
      index:     i,
      y:         hills[i],
      curve:     curves[i],
      grade:     macroGradeSmooth[i],     // world-Y rise per SEG_LENGTH
      gradePct:  realGradePctSmooth[i],   // real-world grade fraction (0.06 = 6%)
      lanes:     traits.lanes,
      roadScale: roadScales[i],
      // Sidewalk gate: only urban segments inside city limits get the
      // concrete band.  Past mile 38 (heading into Snoqualmie Pass)
      // the road is pure forest highway — sidewalks don't belong.
      urban:     (!!traits.buildings) && (mileNow < 38),
      water:     !!traits.water,        // drives bridge guardrails + water tile
      sprites,
      cars: [],
    });
  }

  // ── Mt Baker Tunnel (mile 4.9–5.6) ─────────────────────────────────
  // West portal at the SoDo end of I-90, east portal opens directly
  // onto the Lacey V. Murrow Floating Bridge approach.  Concrete walls
  // + ceiling + roadside scenery stripped.
  {
    const ts = Math.floor(MT_BAKER_TUNNEL_RANGE[0] * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    const te = Math.floor(MT_BAKER_TUNNEL_RANGE[1] * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    for (let i = ts; i !== te; i = (i + 1) % count) {
      const seg = segments[i];
      if (!seg) continue;
      seg.tunnel = true;
      if (seg.sprites?.length) {
        seg.sprites = seg.sprites.filter(sp => sp.isCollectible);
      }
    }
  }

  // ── Mercer Island Lid Tunnel (mile 7.4–7.9) ──────────────────────────
  // After the Murrow floating bridge climbs onto Mercer Island, I-90
  // cuts through a covered "lid" structure across the island ridge.
  // Treated identically to the Mt Baker tunnel — concrete walls +
  // ceiling, water flag cleared so the tile doesn't paint through.
  {
    const ts = Math.floor(MERCER_LID_TUNNEL_RANGE[0] * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    const te = Math.floor(MERCER_LID_TUNNEL_RANGE[1] * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    for (let i = ts; i !== te; i = (i + 1) % count) {
      const seg = segments[i];
      if (!seg) continue;
      seg.tunnel = true;
      // The Mercer lid turns inside the covered structure. Its distant
      // entrance must show an interior back wall before enough curved
      // shell segments are close enough to project visibly.
      seg.curvedTunnelClosure = true;
      seg.water  = false;
      if (seg.sprites?.length) {
        seg.sprites = seg.sprites.filter(sp => sp.isCollectible);
      }
    }
  }

  // ── West Seattle approach (mile 0–1) — water on LEFT side only ─────
  // The road runs along Elliott Bay before climbing onto the high bridge.
  // waterLeft flag triggers a left-flank water render in Road.js while
  // the right flank stays grass for the house frontage.
  {
    const approachStart = 0;
    const approachEnd   = Math.floor(1.0 * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    for (let i = approachStart; i !== approachEnd; i = (i + 1) % count) {
      const seg = segments[i];
      if (!seg) continue;
      seg.waterLeft = true;
    }
  }

  // ── West Seattle Bridge (mile 1.0–1.7) ──────────────────────────────
  // High concrete bridge over the Duwamish.  Mostly over land with two
  // water channels.  Tagged segments get drivable bridge rendering +
  // a hard rail clamp like the tunnel walls.
  // The sprite filter preserves CRANES and the Seattle-skyline-behind-
  // cranes spawns (those were placed by the mile-1.0-1.7 spawn branch
  // upstream); everything else is stripped so random scenery doesn't
  // appear floating in the bridge's water flanks.
  {
    const bridgeStart = Math.floor(WEST_SEATTLE_BRIDGE_RANGE[0] * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    const bridgeEnd   = Math.floor(WEST_SEATTLE_BRIDGE_RANGE[1] * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    // Bridge stretch keeps CRANES + collectibles ONLY.  Cranes are
    // spawned by the mile-1.0-1.7 branch in the spawn block upstream;
    // anything else (Seattle skyline buildings from the regional cycle,
    // homes, etc.) gets stripped so the bridge doesn't look cluttered.
    const isCraneTex = (texKey) =>
      typeof texKey === 'string' && texKey.startsWith('codex_ws_crane_');
    for (let i = bridgeStart; i !== bridgeEnd; i = (i + 1) % count) {
      const seg = segments[i];
      if (!seg) continue;
      seg.bridge = true;
      const mile = i / SEGS_PER_MILE_FOR_TUNNEL(count);
      seg.bridgeWaterChannel = WEST_SEATTLE_WATER_CHANNEL_RANGES.some(
        ([start, end]) => mile >= start && mile < end
      );
      if (seg.sprites?.length) {
        seg.sprites = seg.sprites.filter(sp => sp.isCollectible || isCraneTex(sp.texKey));
      }
    }
  }

  // ── SoDo stadium landmarks ──────────────────────────────────────────
  // Place these as one-off landmarks on the early Seattle approach rather
  // than mixing them into the random skyline pool.  That keeps the drive
  // reading as a sequence: West Seattle/SoDo stadium district → tunnel →
  // bridge → Bellevue.
  {
    const SEGS_PER_MILE = count / TOTAL_ROUTE_MILES;
    const addStadium = (mile, texKey, offset) => {
      const idx = Math.floor(mile * SEGS_PER_MILE) % count;
      const seg = segments[idx];
      if (!seg || seg.bridge || seg.tunnel || seg.water) return;
      seg.sprites = (seg.sprites ?? []).filter(sp => {
        if (sp.isCollectible) return true;
        const off = sp.offset ?? 0;
        return Math.abs(off - offset) > 1.8;
      });
      seg.sprites.push({
        type: 'landmark',
        texKey,
        offset,
        visualMinOffset: Math.abs(offset),
        // Stadium landmarks are now collidable per user spec — they're
        // physical structures at offset ±5.45, so the player would only
        // hit them if they drift well off the road.
        collidable: undefined,
        baseW: 5600,
        baseH: 2600,
        collected: false,
      });
    };
    // Stadium pair — placed right after the West Seattle Bridge exits
    // (bridge ends at mile 1.7) so they read as the SoDo arrival moment.
    // Both on the LEFT side (geographically east of I-90 SoDo stretch).
    // T-Mobile Park comes FIRST (mile 1.85), then Lumen Field (mile 2.00).
    addStadium(1.85, 'codex_seattle_tmobile_park', -5.45);
    addStadium(2.00, 'codex_seattle_lumen_field',  -5.25);
  }

  // ── Lacey V. Murrow Floating Bridge (mile 5.7–7.2) ──────────────────
  // First floating bridge to Mercer Island — emerges right out of the
  // Mt Baker tunnel.  Real-life dead straight (curve flattened above).
  // Water tile + railings, no roadside scenery.
  {
    const ts = Math.floor(MURROW_BRIDGE_RANGE[0] * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    const te = Math.floor(MURROW_BRIDGE_RANGE[1] * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    for (let i = ts; i !== te; i = (i + 1) % count) {
      const seg = segments[i];
      if (!seg) continue;
      seg.bridge = true;
      seg.water  = true;
      if (seg.sprites?.length) {
        seg.sprites = seg.sprites.filter(sp => sp.isCollectible);
      }
    }
  }

  // ── East Channel Bridge (mile 9.8–10.2) ──────────────────────────────
  // Short floating bridge Mercer Island → Bellevue shore.  Same render
  // treatment as the Murrow.
  {
    const ts = Math.floor(EAST_CHANNEL_BRIDGE_RANGE[0] * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    const te = Math.floor(EAST_CHANNEL_BRIDGE_RANGE[1] * SEGS_PER_MILE_FOR_TUNNEL(count)) % count;
    for (let i = ts; i !== te; i = (i + 1) % count) {
      const seg = segments[i];
      if (!seg) continue;
      seg.bridge = true;
      seg.water  = true;
      if (seg.sprites?.length) {
        seg.sprites = seg.sprites.filter(sp => sp.isCollectible);
      }
    }
  }

  // ── Floating-bridge water aprons ─────────────────────────────────────
  // Flag a ~0.10 mi water apron BEFORE and AFTER each lake bridge so the
  // off-road clamps + water-dunk safety net fire when the player drifts
  // sideways into water near a bridge.  Without this, Mercer Island's
  // approach to the East Channel bridge let the player drive off into
  // the lake (regular land segment → no water rail) even though the
  // visual water is painted around the road. The high West Seattle port
  // bridge is excluded: it crosses mostly paved port land interrupted by
  // two channels, not open lake water. Only the `water` flag is set on
  // aprons (not `bridge`) so structure does not render outside its range.
  {
    const APRON_MI = 0.10;
    const segsPerMi = SEGS_PER_MILE_FOR_TUNNEL(count);
    const apronSegs = Math.floor(APRON_MI * segsPerMi);
    for (const range of [MURROW_BRIDGE_RANGE, EAST_CHANNEL_BRIDGE_RANGE]) {
      const ts = Math.floor(range[0] * segsPerMi) % count;
      const te = Math.floor(range[1] * segsPerMi) % count;
      // Pre-bridge apron (entering the bridge).
      for (let k = 1; k <= apronSegs; k++) {
        const idx = (ts - k + count) % count;
        const seg = segments[idx];
        if (!seg || seg.bridge) continue;
        seg.water = true;
        if (seg.sprites?.length) {
          seg.sprites = seg.sprites.filter(sp => sp.isCollectible);
        }
      }
      // Post-bridge apron (leaving the bridge).
      for (let k = 0; k < apronSegs; k++) {
        const idx = (te + k) % count;
        const seg = segments[idx];
        if (!seg || seg.bridge) continue;
        seg.water = true;
        if (seg.sprites?.length) {
          seg.sprites = seg.sprites.filter(sp => sp.isCollectible);
        }
      }
    }
  }

  // ── Random roadside cops — every 15–30 miles, 50/50 parked vs driving.
  //
  // Parked cops sit on the shoulder facing the road (left or right side
  // → uses car_left_police / car_right_police side-view art).  Driving
  // cops cruise in same-direction lanes alongside other traffic, using
  // the back-view police art.
  //
  // GameScene watches for the player passing one of these (with stars ≥ 1)
  // and converts the encounter into an active rear-pursuit cop.
  const SEGS_PER_MILE = count / TOTAL_ROUTE_MILES;
  let mile = 18 + rng.range(0, 12);                 // first cop at mile 18-30
  while (mile < TOTAL_ROUTE_MILES - 1) {
    const segIdx = Math.floor(mile * SEGS_PER_MILE) % count;
    const seg    = segments[segIdx];
    if (seg) {
      const parked   = rng.bool(0.5);
      const sideRight = rng.bool(0.5);
      seg.sprites.push({
        type:        parked ? 'cop_random_parked' : 'cop_random_driving',
        offset:      parked
          ? (sideRight ? rng.range(1.20, 1.45) : -rng.range(1.20, 1.45))  // shoulder
          : (rng.bool(0.5) ? 0.25 : 0.65),                                  // same-direction lane
        side:        parked ? (sideRight ? 'right' : 'left') : null,
        baseW:       parked ? 700 : 600,
        baseH:       parked ? 900 : 1000,
        collected:   false,
        copEncounter: true,                          // GameScene flag
        triggered:   false,
      });
    }
    mile += 15 + rng.range(0, 15);                  // next cop 15–30 mi later
  }

  // ── Rest-stop signage + exit ramp markers ─────────────────────────────
  // For each rest stop drop a sign sprite at −5 mi and −1 mi plus the
  // exit-ramp marker at the stop itself. Spread each sign across a small
  // segment range so the player gets multiple chances to see it as the
  // road scrolls — a single one-segment sprite was too easy to miss in
  // tree clutter.
  //
  // ALSO: tag a 0.25-mile-wide window of segments leading into the stop
  // with a `rampStrength` value (0 → 1 as the player nears the stop). This
  // drives Road.js's exit-ramp painting so the asphalt visibly tapers off
  // to the right just like a real off-ramp.
  // Match the trigger window (1.0 mi before stop, 0.3 mi after) so the
  // painted ramp covers EVERY segment where the player can take the exit
  // — no dead zones where the rest-stop window is open but the asphalt
  // hasn't been painted yet.
  const RAMP_WINDOW_SEG = Math.floor(1.0 / TOTAL_ROUTE_MILES * count); // ≈1442 segs ≈ 1 mi
  // ── Real mileage signs at every checkpoint ──────────────────────────
  // For each location in CHECKPOINTS (every named town/landmark in the
  // route), drop a green I-90-style location sign 1 mile before the
  // location's start mile.  Replaces the random brown signs that used
  // to clutter the shoulder.  (SEGS_PER_MILE is already declared above
  // for the random-cop placement loop.)
  // If a sign target lands INSIDE a tunnel, walk backward until we
  // clear the tunnel mouth — signs are never readable when projected
  // through a concrete ceiling.
  const beforeTunnel = (segIdx) => {
    if (segIdx == null || segIdx < 0) return segIdx;
    let cur = segIdx;
    for (let k = 0; k < 1200 && segments[cur]?.tunnel; k++) {
      cur = (cur - 1 + count) % count;
    }
    return cur;
  };

  for (const cp of CHECKPOINTS) {
    if (cp.isStart) continue;                       // skip "West Seattle" — it IS the start
    // Skip checkpoints that share their mile with a REST_STOP — the
    // rest-stop signage suite (5mi advance, exit sign, amenities placard)
    // already labels that location, so a mileage_sign painted at cp.mileage-1
    // would overlap the exit_sign_green at rs.mileage-1 and double the text.
    const sharesWithRestStop = REST_STOPS.some(rs => Math.abs(rs.mileage - cp.mileage) < 1.5);
    if (sharesWithRestStop) continue;
    const advanceMile = Math.max(0, cp.mileage - 1);
    let segIdx = Math.floor(advanceMile * SEGS_PER_MILE) % count;
    if (segIdx < 0 || segIdx >= count) continue;
    segIdx = beforeTunnel(segIdx);
    // (Removed: stand-alone `mileage_sign` — green town/exit/mileage
    //  marker carried no drug info, so per UX direction it's now
    //  suppressed.  The exit_sign_green at rest stops still carries
    //  the route info AND drug bars.)
    // segments[segIdx].sprites.push({ type: 'mileage_sign', ... });
  }

  // Helper — clear right-side scenery (trees, buildings, etc.) from a
  // window of segments around a sign placement so the sign is never
  // visually blocked.  Span is in segments; default ≈ 0.05 mi before and
  // 0.10 mi after — enough that the player has a clear approach view.
  const clearRightSceneryAround = (centerSeg, before = 80, after = 140) => {
    for (let k = -before; k <= after; k++) {
      const idx = ((centerSeg + k) % count + count) % count;
      const seg = segments[idx];
      if (!seg?.sprites) continue;
      seg.sprites = seg.sprites.filter(sp => {
        if (sp.type === 'rest_sign') return true;
        if (sp.type === 'exit_sign_green') return true;
        if (sp.type === 'amenities_sign') return true;
        if (sp.type === 'mileage_sign') return true;
        if (sp.type === 'grade_sign') return true;
        if (sp.type === 'next_stops_sign') return true;
        if (sp.isCollectible)         return true;
        // City skyline buildings get stored at a close offset (~2.05) but
        // render at visualMinOffset (CITY_BUILDING_SETBACK = 5.35) — they
        // visually sit OUTSIDE the exit corridor.  Preserve them so the
        // right side of Bellevue / downtown Seattle doesn't read empty.
        if ((sp.visualMinOffset ?? 0) >= CITY_BUILDING_SETBACK) return true;
        const off = sp.offset ?? 0;
        if (off > 1.0 && off < 4.9)   return false;     // strip exit-lane corridor
        return true;
      });
    }
  };

  // ── Steep-grade warning signs ─────────────────────────────────────────
  // Real I-90 has yellow regulatory signs ahead of the major sustained
  // grades.  Spawn them just before the top of each big climb/descent so
  // the player gets the same visual cue trucks do.
  const GRADE_SIGNS = [
    // Eastbound descent off Snoqualmie summit (mi 52→62, ~3-4% sustained)
    { mile: 51,  line1: 'TRUCKS USE',   line2: 'LOWER GEAR' },
    { mile: 53,  line1: '6% GRADE',     line2: 'NEXT 10 MI' },
    // Ryegrass Summit drop into Vantage (mi 122→132, the route's most
    // dramatic descent — 1965 ft drop in 10 mi, 4-5% in places).
    { mile: 121, line1: 'STEEP GRADE',  line2: 'NEXT 10 MI' },
    { mile: 123, line1: 'TRUCKS USE',   line2: 'LOWER GEAR' },
    // Westbound climb up Snoqualmie (32→52, 2497 ft over 20 mi)
    { mile: 33,  line1: 'STEEP CLIMB',  line2: 'CHAIN-UP AHEAD' },
    // Snow-zone warnings ahead of the white-out (Phase 3 weather)
    { mile: 38,  line1: 'CHAINS',       line2: 'REQUIRED' },
    { mile: 39,  line1: 'TRACTION',     line2: 'TIRES ADVISED' },
    // Climb out of Vantage (132→140)
    { mile: 133, line1: '6% GRADE',     line2: 'NEXT 8 MI' },
  ];
  for (const gs of GRADE_SIGNS) {
    let segIdx = Math.floor(gs.mile * SEGS_PER_MILE) % count;
    if (segIdx < 0 || segIdx >= count) continue;
    segIdx = beforeTunnel(segIdx);
    segments[segIdx].sprites.push({
      type:    'grade_sign',
      line1:   gs.line1,
      line2:   gs.line2,
      // offset 1.6: grade_sign is a smaller diamond plaque (baseW
      // 2800) — face fits within ~1.0 road units wide, so offset
      // 1.6 keeps it fully clear of the road (face spans ~1.1 to 2.1).
      offset:  1.6,
      baseW:   2800, baseH: 3400,
      collected: false,
    });
    clearRightSceneryAround(segIdx, 60, 100);
  }

  // Apply to the mileage signs (CHECKPOINT name signs) we just placed.
  // Skip checkpoints that share their mile with a REST_STOP — those
  // weren't given a mileage_sign in the loop above, so there's nothing
  // to clear scenery around.
  for (const cp of CHECKPOINTS) {
    if (cp.isStart) continue;
    if (REST_STOPS.some(rs => Math.abs(rs.mileage - cp.mileage) < 1.5)) continue;
    const advanceMile = Math.max(0, cp.mileage - 1);
    const segIdx = Math.floor(advanceMile * SEGS_PER_MILE) % count;
    clearRightSceneryAround(segIdx);
  }

  for (const [rsIdx, rs] of REST_STOPS.entries()) {
    const segAt = (mi) => Math.floor((mi / TOTAL_ROUTE_MILES) * count) % count;
    // (Removed: stand-alone `rest_sign` placards — both the −5mi
    //  "REST AREA AHEAD" sign and the "EXIT" sign carried no drug
    //  info, so per UX direction they're suppressed.  The
    //  exit_sign_green spawned 1 mile out still announces the stop
    //  AND carries the drug bars.)
    const placeSign = (_centerSeg, _sub) => {};
    placeSign(segAt(rs.mileage - 5), '5mi');
    placeSign(segAt(rs.mileage),     'exit');
    // Clear approach scenery around each rest-stop sign so trees/buildings
    // can't hide them.  The exit-window sign falls within the ramp clear
    // band; the −5mi advance sign and the new −1mi green exit sign +
    // −0.75mi amenities preview both sit outside it.
    clearRightSceneryAround(segAt(rs.mileage - 5));
    clearRightSceneryAround(segAt(rs.mileage - 1));      // green sign lives here
    clearRightSceneryAround(segAt(rs.mileage - 0.75));   // amenities placard

    // Big green I-90-style overhead exit sign 1 mi before the stop. The
    // sign reads EXIT <label> + town and now carries the highway shield
    // badge in the top-left corner (composited by GameScene).  Single-
    // segment placement (multiple copies stacked = ghost effect).
    // GUARD: if the −1 mi spot is on a bridge / in a tunnel / over water,
    // walk forward to the next dry segment so the sign isn't planted in
    // the lake or through tunnel walls.
    const findDrySeg = (startSegIdx, maxSearch = 400) => {
      // Tunnel case: walk BACKWARD so the sign sits just before the
      // tunnel mouth (visible to the player on approach) instead of
      // being pushed past the tunnel exit.
      if (segments[startSegIdx]?.tunnel) {
        for (let k = 0; k < 1200; k++) {
          const idx = (startSegIdx - k + count) % count;
          const seg = segments[idx];
          if (seg && !seg.tunnel && !seg.bridge && !seg.water) return idx;
        }
      }
      // Bridge/water case: walk forward to the next dry segment.
      for (let k = 0; k < maxSearch; k++) {
        const idx = (startSegIdx + k) % count;
        const seg = segments[idx];
        if (seg && !seg.bridge && !seg.tunnel && !seg.water) return idx;
      }
      return startSegIdx;
    };
    const greenSegIdx = findDrySeg(((segAt(Math.max(0, rs.mileage - 1)) % count) + count) % count);
    segments[greenSegIdx].sprites.push({
      type:      'exit_sign_green',
      sub:       'green',
      stopId:    rs.id,
      exitLabel: rs.exit ?? `Mile ${rs.mileage}`,   // "Exit 7B", "WA-262", etc.
      mileage:   rs.mileage,
      townName:  rs.name.split(',')[0],             // strip ", WA"
      hwyKey:    rs.hwy ?? 'hwy_i90',               // shield badge texture
      // offset 2.0: sign FACE is 1.32 * baseW / ROAD_WIDTH = 1.76 road
      // units wide (half = 0.88), so the face spans offset 1.12 to 2.88
      // — fully off the road (road ends at offset 1.0).  Previously 1.20
      // which centered the face directly over the right lane.
      offset:    2.0,
      baseW: 4800, baseH: 6600,                     // bumped — big I-90 overhead sign
      collected: false,
    });

    // Amenities preview placard 0.75 mi before the stop (¼ mi after the
    // exit sign).  Sized to match exit_sign_green so the placard is held
    // up off the ground by tall steel legs (face occupies the upper ~62 %
    // of the sprite area, legs reach down to the road surface).  The
    // pre-baked PNG is overlaid by GameScene._renderSignDecals at the
    // PNG's natural 1277:840 aspect, centered inside the white frame
    // painted by Road.js's case 'amenities_sign'.
    const amenSegIdx = findDrySeg(((segAt(Math.max(0, rs.mileage - 0.75)) % count) + count) % count);
    segments[amenSegIdx].sprites.push({
      type:       'amenities_sign',
      stopId:     rs.id,
      amenities:  rs.amenities ?? [],
      signKey:    `sign_${rs.id}`,                   // pre-baked PNG key
      // offset 2.4: largest sign (baseW 6700, face 1.30w → 2.42 road
      // units wide, half = 1.21).  Face spans offset 1.19 to 3.61 —
      // fully clear of the road (road ends at 1.0).
      offset:     2.4,
      // ~40% larger than the previous 4800×6600 baseline so the
      // baked-in brand logos read clearly from approach distance —
      // matches the reference "SHOPPING — NEXT RIGHT" placard.
      baseW: 6700, baseH: 9200,
      collected:  false,
    });

    // Paint the actual exit ramp.  rampStrength ramps 0 → 1 over the last
    // RAMP_WINDOW segments; Road.js reads it to widen the right shoulder
    // and draw a tapered "off-ramp" trapezoid.
    //
    // GUARD: skip any segment flagged bridge / tunnel / water so the ramp
    // is never painted out over a lake or through tunnel walls.  When the
    // window crosses a bridge (e.g. Mercer Island after the LV Murrow,
    // Bellevue after the East Channel) we re-base `t` so the ramp grows
    // from 0 at the first DRY segment up to 1 at the exit point — that
    // way the off-ramp opens cleanly off the bridge without an abrupt
    // mid-window pop-in.
    const exitSeg = segAt(rs.mileage);
    const isWet = (s) => !!(s?.bridge || s?.tunnel || s?.water);
    let dryStart = 0;
    for (let k = 0; k < RAMP_WINDOW_SEG; k++) {
      const segIdx = (exitSeg - RAMP_WINDOW_SEG + 1 + k + count) % count;
      if (!isWet(segments[segIdx])) { dryStart = k; break; }
    }
    const dryRange = Math.max(1, RAMP_WINDOW_SEG - dryStart);
    for (let k = dryStart; k < RAMP_WINDOW_SEG; k++) {
      const segIdx = (exitSeg - RAMP_WINDOW_SEG + 1 + k + count) % count;
      const seg = segments[segIdx];
      if (!seg) continue;
      if (isWet(seg)) continue;                  // never paint over water/bridge/tunnel
      const t = (k - dryStart) / dryRange;       // 0 (first dry seg) → 1 (at exit)
      seg.rampStrength = Math.max(seg.rampStrength ?? 0, t);
      seg.rampStopId   = rs.id;
    }
    // After-exit window — extend to 0.3 mi to match the trigger window's
    // winAfter so the ramp is paved for the player's whole pull-over zone.
    const AFTER_SEGS = Math.floor(0.3 / TOTAL_ROUTE_MILES * count);
    for (let k = 1; k < AFTER_SEGS; k++) {
      const segIdx = (exitSeg + k) % count;
      const seg = segments[segIdx];
      if (!seg) continue;
      if (isWet(seg)) continue;                  // same guard on the after-window
      seg.rampStrength = Math.max(seg.rampStrength ?? 0, 1 - k / AFTER_SEGS);
      seg.rampStopId   = rs.id;
    }
    // ── Hitchhikers at the on/off-ramp ───────────────────────────────
    // Seed 1-2 hitchhiker sprites along the ramp window so they ONLY
    // appear at exits / rest stops, not on the open highway.  Offsets
    // pushed further left (-1.10 to -1.25) so a player coasting in the
    // travel lanes doesn't brush them — they require a deliberate
    // pull-toward-the-shoulder to be collected.
    {
      const hhCount = 1 + (rng.next() < 0.5 ? 1 : 0);
      for (let h = 0; h < hhCount; h++) {
        // Pick a segment ~25-75 % into the approach ramp window.
        const t = 0.25 + rng.next() * 0.50;
        const k = Math.floor(t * RAMP_WINDOW_SEG);
        const hhIdx = (exitSeg - RAMP_WINDOW_SEG + 1 + k + count) % count;
        const seg = segments[hhIdx];
        if (!seg || isWet(seg)) continue;
        seg.sprites.push({
          type:            'hitchhiker',
          offset:          -(1.10 + rng.next() * 0.15),
          baseW:  80, baseH: 200,
          collected:       false,
          isCollectible:   true,
          collectibleType: 'hitchhiker',
        });
      }
    }

    // Clear the exit-lane corridor, not the entire right roadside.  At
    // full divergence Road.js paints the ramp from roughly x=3.05 to
    // x=4.30; include the gore/shoulder margins, but preserve scenery
    // farther out so the right side still feels populated.
    // Keep the heavy non-skyline corridor wipe short, but apply skyline
    // clearance across the FULL ramp approach. The Bellevue ramp is already
    // visibly painted around mile 11.96 for the 12.5 exit, so a 0.35-mile
    // skyline cleanup misses the exact buildings the player sees there.
    const RAMP_CLEAR_BEFORE_SEG = Math.floor(0.35 / TOTAL_ROUTE_MILES * count);
    const RAMP_SKYLINE_BEFORE_SEG = RAMP_WINDOW_SEG;
    const RAMP_SKYLINE_SETBACK = CITY_BUILDING_SETBACK + 3.2;
    const rampSkylineWindowFull = RAMP_SKYLINE_BEFORE_SEG + AFTER_SEGS;
    for (let k = 0; k < rampSkylineWindowFull; k++) {
      const segIdx = (exitSeg - RAMP_SKYLINE_BEFORE_SEG + 1 + k + count) % count;
      const seg = segments[segIdx];
      if (!seg?.sprites) continue;
      for (const sp of seg.sprites) {
        if ((sp.visualMinOffset ?? 0) < CITY_BUILDING_SETBACK) continue;
        const off = sp.offset ?? 0;
        const side = off >= 0 ? 1 : -1;
        const nextOffset = Math.max(Math.abs(off), RAMP_SKYLINE_SETBACK);
        sp.visualMinOffset = Math.max(sp.visualMinOffset ?? 0, RAMP_SKYLINE_SETBACK);
        sp.offset = side * nextOffset;
        sp.rampClearance = true;
      }
    }

    // Trees are allowed beside an exit, but never planted on its paved
    // lane. Clear the whole painted approach, not only the final merge
    // area, since the first Seattle exit already shows the ramp for a
    // full mile before the stop.
    const rampTreeWindowFull = RAMP_WINDOW_SEG + AFTER_SEGS;
    for (let k = 0; k < rampTreeWindowFull; k++) {
      const segIdx = (exitSeg - RAMP_WINDOW_SEG + 1 + k + count) % count;
      const seg = segments[segIdx];
      if (!seg?.sprites) continue;
      seg.sprites = seg.sprites.filter(sp => {
        const off = sp.offset ?? 0;
        return sp.type !== 'tree' || off <= 1.0 || off >= 4.9;
      });
    }

    const rampWindowFull = RAMP_CLEAR_BEFORE_SEG + AFTER_SEGS;
    for (let k = 0; k < rampWindowFull; k++) {
      const segIdx = (exitSeg - RAMP_CLEAR_BEFORE_SEG + 1 + k + count) % count;
      const seg = segments[segIdx];
      if (!seg?.sprites) continue;
      seg.sprites = seg.sprites.filter(sp => {
        // Always keep rest-stop signs and gameplay collectibles regardless of side.
        if (sp.type === 'rest_sign') return true;
        if (sp.type === 'exit_sign_green') return true;
        if (sp.type === 'amenities_sign') return true;
        if (sp.type === 'next_stops_sign') return true;
        if (sp.isCollectible)        return true;
        // rampClearance sprites are already pushed past the gore by the
        // renderer — don't wipe them on top of that.
        if (sp.rampClearance)        return true;
        const off = sp.offset ?? 0;
        if ((sp.visualMinOffset ?? 0) >= CITY_BUILDING_SETBACK) {
          return true;
        }
        if (off > 1.0 && off < 4.9) return false;
        return true;
      });
    }

    // Perspective roadside strip near the actual exit handoff. This uses
    // the generated low-shop / side-street strip, placed close enough to
    // read as exit scenery instead of tiny buildings far off in the field.
    // Skipped for residential rest stops (Mercer Island — only "camp"
    // amenity) where a commercial-strip image reads as a tiny floating
    // sticker rather than fitting the single-family neighborhood feel.
    // Bellevue already has horizon-anchored skyline strips; adding this
    // as a normal roadside sprite made a floating apartment-card near
    // the road instead of a stable horizon element.
    if (rs.id !== 'M' && rs.id !== 'B') {
      const addExitScenery = (mile, offset) => {
        const segIdx = findDrySeg(((segAt(mile) % count) + count) % count);
        const seg = segments[segIdx];
        if (!seg || isWet(seg)) return;
        const texKey = rs.mileage <= 13
          ? 'codex_bellevue_roadside_strip'
          : 'codex_issaquah_roadside_strip_perspective';
        seg.sprites = seg.sprites ?? [];
        seg.sprites.push({
          type: 'building',
          texKey,
          offset,
          visualMinOffset: Math.abs(offset),
          // Exit-ramp shop strip is now collidable per user spec.
          // Player on the exit ramp at p.x up to ~2.8 will hit this
          // strip at offset 2.65 (collision band 1.80-3.50).
          collidable: undefined,
          heightBoost: 1.0,
          baseW: 7600,
          baseH: 1700,
          collected: false,
        });
      };
      addExitScenery(rs.mileage - 0.08, 2.65);
    }
  }

  // ── "Next exits" placards every 10 miles ──────────────────────────────
  // Tall green sign listing the next 3 upcoming rest stops + their mile
  // counts.  Placed 10 mi past Seattle through to the last rest stop, but
  // skipped if too close to an existing exit/amenities placard (those
  // already advertise the next stop) and skipped if the segment is on
  // a bridge or in a tunnel.
  const NEXT_STOPS_INTERVAL_MI = 10;
  const NEXT_STOPS_AVOID_MI    = 1.2;   // skip if within 1.2 mi of any rest stop
  for (let mi = NEXT_STOPS_INTERVAL_MI; mi < TOTAL_ROUTE_MILES - 5; mi += NEXT_STOPS_INTERVAL_MI) {
    // Skip if too close to a rest-stop sign zone (those already preview the next exit).
    const tooClose = REST_STOPS.some(rs => Math.abs(rs.mileage - mi) < NEXT_STOPS_AVOID_MI);
    if (tooClose) continue;
    const segIdx = Math.floor((mi / TOTAL_ROUTE_MILES) * count) % count;
    const seg    = segments[segIdx];
    if (!seg) continue;
    if (seg.bridge || seg.tunnel || seg.water) continue;
    // Build the next-3-stops list (deduped, only stops AHEAD of this mile).
    const upcoming = REST_STOPS
      .filter(rs => rs.mileage > mi)
      .slice(0, 3)
      .map(rs => ({ name: rs.name.split(',')[0], mi: Math.round(rs.mileage - mi) }));
    if (upcoming.length === 0) continue;
    seg.sprites.push({
      type:      'next_stops_sign',
      rows:      upcoming,
      // offset 2.0: face is 1.24 * 4400 / ROAD_WIDTH = 1.52 road units
      // wide (half = 0.76).  Face spans offset 1.24 to 2.76 — fully
      // clear of the road.  Previously 1.18 which centered the face
      // over the right lane.
      offset:    2.0,
      baseW: 4400, baseH: 6200,
      collected: false,
    });
    clearRightSceneryAround(segIdx, 70, 120);
  }

  // ── Landmark: Space Needle ─────────────────────────────────────────
  // Real geography: driving I-90 east, the Space Needle is north (LEFT)
  // of the highway, visible from the West Seattle Bridge looking
  // northeast.  Place at mile 3.5 — just past the bridge exit and
  // past the cranes (1.05–1.75) so it reads as a distant downtown
  // landmark over the cranes' shoulders while crossing the bridge.
  // Needs far-perspective scaling (see _renderSceneSprites) so it
  // renders at horizon size from miles 1.0–1.7.
  const needleSeg = Math.floor((3.5 / TOTAL_ROUTE_MILES) * count) % count;
  segments[needleSeg].sprites.push({
    type:      'landmark',
    texKey:    'space_needle',
    offset:    -1.6,               // LEFT side of the road (north of I-90)
    baseW:     2500, baseH: 2500,
    renderDepth: 1.5,              // behind cranes (2.0) and most scenery
    collected: false,
  });

  return segments;
}

/**
 * Weapon drop table — split evenly between forward-firing and rear-facing
 * tools so the player can defend both sides at roughly the same rate.
 *
 *   Forward (kills front cops):  gun, rocket   → 50% combined
 *   Backward (kills rear cops):  spike, paint  → 50% combined
 *
 * Rockets are bidirectional in CopSystem.useF12Token so the rocket pickup
 * itself counts toward "balanced" because the player chooses direction at
 * fire time via the weapon-cycle button.
 */
function pickF12(rng) {
  const r = rng.next();
  if (r < 0.30) return 'f12_gun';     // 30% — forward
  if (r < 0.50) return 'f12_rocket';  // 20% — bidirectional (player picks)
  if (r < 0.75) return 'f12_spike';   // 25% — backward
  return 'f12_paint';                  // 25% — backward
}

function pickCollectible(rng, routeProgress) {
  if (routeProgress < 0.25) return rng.bool(0.7) ? 'beer' : 'weed';
  if (routeProgress < 0.45) return rng.pick(['beer', 'beer', 'weed', 'cocaine']);
  return rng.pick(['beer', 'weed', 'cocaine', 'beer', 'weed']);
}
